Application::Application() 
{
    // Initialize the event group for inter-task communication
    m_eventGroup = xEventGroupCreate();
    if (m_eventGroup == NULL) {
        // Handle event group creation failure
        ErrorHandler::HandleError(ERROR_EVENT_GROUP_CREATION_FAILED);
        return;
    }

    // Initialize AEC mode based on configuration
    AecMode aecMode = ConfigManager::GetInstance().GetAecMode();

    // Ensure mutual exclusivity between device and server AEC
    bool deviceAecEnabled = false;
    bool serverAecEnabled = false;

    switch (aecMode) {
        case AEC_MODE_DEVICE_SIDE:
            deviceAecEnabled = true;
            serverAecEnabled = false;
            break;
        case AEC_MODE_SERVER_SIDE:
            deviceAecEnabled = false;
            serverAecEnabled = true;
            break;
        case AEC_MODE_DISABLED:
        default:
            deviceAecEnabled = false;
            serverAecEnabled = false;
            break;
    }

    // Configure AEC modules based on the selected mode
    if (deviceAecEnabled) {
        mAecModule.Initialize(DEVICE_AEC_CONFIG);
    } else if (serverAecEnabled) {
        mAecModule.Initialize(SERVER_AEC_CONFIG);
    } else {
        mAecModule.Disable();
    }

    // Set up periodic timer for clock tick events
    m_clockTimer = xTimerCreate(
        "ClockTickTimer",
        pdMS_TO_TICKS(CONFIG_CLOCK_TICK_INTERVAL_MS),
        pdTRUE,  // Auto-reload
        this,    // Timer ID
        ClockTickCallback
    );

    if (m_clockTimer == NULL) {
        // Handle timer creation failure
        ErrorHandler::HandleError(ERROR_TIMER_CREATION_FAILED);
        return;
    }

    // Start the periodic timer
    BaseType_t timerStartResult = xTimerStart(m_clockTimer, portMAX_DELAY);
    if (timerStartResult != pdPASS) {
        ErrorHandler::HandleError(ERROR_TIMER_START_FAILED);
        return;
    }

    // Initialize core event management system
    m_eventManager.Initialize(m_eventGroup);

    // Mark application as initialized
    m_initialized = true;
}

void Initialize()
{
    // Initialize display system
    Display_Init();
    Display_SetBrightness(100);
    Display_ClearScreen();

    // Initialize audio service
    AudioService_Init();
    AudioService_SetVolume(50);
    AudioService_RegisterCallback(AudioProcessingCallback);

    // Initialize network interface
    Network_Init();
    Network_RegisterEventCallback(NetworkEventHandler);
    Network_ConnectToDefaultAP();

    // Register device state change callbacks
    DeviceManager_RegisterStateCallback(DeviceStateChangeHandler);

    // Set up user notification system
    Notification_Init();
    Notification_SetDisplayCallback(DisplayNotification);

    // Start periodic timers
    Timer_CreatePeriodic(AudioProcessingTimer, 100);  // 100ms audio processing
    Timer_CreatePeriodic(NetworkStatusTimer, 5000);   // 5s network check
    Timer_CreatePeriodic(SystemHealthTimer, 30000);   // 30s system health

    // Register common tools for MCP server
    MCP_RegisterTool("display_ctrl", DisplayControlTool);
    MCP_RegisterTool("audio_ctrl", AudioControlTool);
    MCP_RegisterTool("network_info", NetworkInfoTool);
    MCP_RegisterTool("system_status", SystemStatusTool);

    // Final system configuration
    System_SetOperatingMode(MODE_NORMAL);
    Logger_Log(LOG_INFO, "System initialization completed successfully");
}

void Run() {
    // Initialize system state
    bool running = true;
    SystemState currentState = STATE_IDLE;
    Event event;

    // Main event loop
    while (running) {
        // Poll for events with timeout to prevent blocking
        if (GetNextEvent(&event, 100)) { // 100ms timeout
            // Process different types of events
            switch (event.type) {
                case EVENT_NETWORK_CHANGE:
                    HandleNetworkChange(event.data);
                    break;

                case EVENT_AUDIO_COMMAND:
                    HandleAudioCommand(event.data);
                    break;

                case EVENT_STATE_TRANSITION:
                    currentState = HandleStateTransition(event.data);
                    UpdateUI(currentState);
                    break;

                case EVENT_CHAT_TOGGLE:
                    ToggleChatMode();
                    UpdateUI(currentState);
                    break;

                case EVENT_LISTENING_START:
                    EnterListeningState();
                    UpdateUI(STATE_LISTENING);
                    break;

                case EVENT_LISTENING_STOP:
                    ExitListeningState();
                    UpdateUI(currentState);
                    break;

                case EVENT_ERROR:
                    HandleError(event.data);
                    LogError(event.data);
                    AttemptRecovery();
                    break;

                case EVENT_SCHEDULED_TASK:
                    ExecuteScheduledTask(event.data);
                    break;

                case EVENT_SYSTEM_SHUTDOWN:
                    running = false;
                    break;

                default:
                    // Handle unknown events
                    LogWarning("Unknown event type received");
                    break;
            }
        }

        // Perform periodic tasks
        ProcessScheduledTasks();

        // Update device state if needed
        UpdateDeviceState();

        // Handle any pending UI updates
        RefreshUI();

        // Check system health
        if (!CheckSystemHealth()) {
            HandleSystemError(ERROR_CRITICAL_FAILURE);
            AttemptRecovery();
        }

        // Yield to other processes/threads if necessary
        YieldProcessor();
    }

    // Cleanup before exit
    CleanupResources();
    ShutdownComponents();
}

void HandleNetworkConnectedEvent()
{
    // Update device state to reflect network connected status
    DeviceStateManager::GetInstance()->SetNetworkState(NETWORK_STATE_CONNECTED);

    // Open or resume audio channels that may have been paused during disconnection
    AudioManager::GetInstance()->OpenActiveAudioChannel();

    // Update display to show connected status
    DisplayManager::GetInstance()->UpdateNetworkStatus(true); // true = connected

    // Handle device state transitions
    DeviceStateManager::GetInstance()->TransitionToState(DEVICE_STATE_ONLINE);

    // Play success sound to indicate connection established
    SoundPlayer::GetInstance()->PlaySound(SOUND_NETWORK_CONNECTED);

    // Log the event for debugging purposes
    Logger::LogInfo("Network connected event handled successfully");

    // Notify other subsystems about the connection
    EventManager::GetInstance()->NotifyNetworkConnected();
}

