bool CheckAssetsVersion() {
    // Initialize status variables
    bool success = false;
    int retryCount = 0;
    const int MAX_RETRIES = 3;
    const int PROGRESS_CHECK_INTERVAL = 1000; // ms

    // Display initial status
    UpdateDisplay("Checking asset versions...");
    SetProgress(0);

    // Manage hardware power state
    EnableHighPowerMode();

    try {
        // Step 1: Get current asset versions
        UpdateDisplay("Retrieving current asset information...");
        SetProgress(10);

        AssetInfo currentAssets = GetCurrentAssetVersions();
        if (currentAssets.IsEmpty()) {
            LogError("Failed to retrieve current asset versions");
            UpdateDisplay("Error: Cannot retrieve current assets");
            throw std::runtime_error("Asset retrieval failed");
        }

        // Step 2: Check for new firmware versions with retry logic
        UpdateDisplay("Checking for firmware updates...");
        SetProgress(20);

        FirmwareInfo newFirmware;
        bool firmwareCheckSuccess = false;

        while (retryCount < MAX_RETRIES && !firmwareCheckSuccess) {
            try {
                newFirmware = CheckForNewFirmware();
                firmwareCheckSuccess = true;
            } catch (const NetworkException& e) {
                retryCount++;
                LogWarning("Network error checking firmware (attempt " + std::to_string(retryCount) + ")");

                if (retryCount < MAX_RETRIES) {
                    UpdateDisplay("Network error, retrying...");
                    Delay(2000); // Wait before retry
                } else {
                    UpdateDisplay("Failed to check firmware after retries");
                    LogError("Firmware check failed after " + std::to_string(MAX_RETRIES) + " attempts");
                }
            }
        }

        // Alert user if new firmware is available
        if (firmwareCheckSuccess && newFirmware.IsNewerThanCurrent()) {
            AlertUser("New firmware version " + newFirmware.version + " available");
            SetProgress(25);
        }

        // Step 3: Check for asset updates
        UpdateDisplay("Checking for asset updates...");
        SetProgress(30);

        AssetUpdateInfo updateInfo = GetAssetUpdateInfo(currentAssets);

        if (updateInfo.HasUpdates()) {
            // Notify user about available updates
            AlertUser("Asset updates available: " + std::to_string(updateInfo.updateCount) + " files");

            // Step 4: Download new assets
            UpdateDisplay("Downloading assets...");
            SetProgress(40);

            DownloadResult downloadResult = DownloadAssets(updateInfo);

            if (downloadResult.success) {
                UpdateDisplay("Download complete, applying updates...");
                SetProgress(70);

                // Step 5: Apply downloaded assets
                ApplyResult applyResult = ApplyAssets(downloadResult.downloadedFiles);

                if (applyResult.success) {
                    UpdateDisplay("Assets updated successfully");
                    SetProgress(90);

                    // Update asset version tracking
                    SaveAssetVersions(updateInfo.newVersions);

                    // Notify completion
                    AlertUser("Asset update completed successfully");
                    success = true;
                } else {
                    LogError("Failed to apply assets: " + applyResult.errorMessage);
                    UpdateDisplay("Error applying assets: " + applyResult.errorMessage);
                }
            } else {
                LogError("Failed to download assets: " + downloadResult.errorMessage);
                UpdateDisplay("Download failed: " + downloadResult.errorMessage);
            }
        } else {
            UpdateDisplay("Assets are up to date");
            SetProgress(95);
            success = true;
        }

        // Step 6: Finalize and cleanup
        if (success) {
            UpdateDisplay("Asset check completed successfully");
            SetProgress(100);
        }

    } catch (const std::exception& e) {
        LogError("Exception in CheckAssetsVersion: " + std::string(e.what()));
        UpdateDisplay("Critical error occurred");
        AlertUser("Asset update process failed");
        success = false;
    } catch (...) {
        LogError("Unknown exception in CheckAssetsVersion");
        UpdateDisplay("Unknown error occurred");
        success = false;
    }

    // Restore power management
    RestorePowerMode();

    return success;
}

bool CheckNewVersion()
{
    // Initialize return status - assume no update needed
    bool updateAvailable = false;

    // Get current firmware version from device storage
    FirmwareVersion currentVersion;
    if (!GetStoredFirmwareVersion(currentVersion)) {
        LogError("Failed to retrieve current firmware version");
        return false;
    }

    // Connect to update server if not already connected
    if (!IsUpdateServerConnected()) {
        if (!ConnectToUpdateServer()) {
            LogError("Failed to connect to update server");
            return false;
        }
    }

    // Query server for latest firmware version
    FirmwareVersion latestVersion;
    UpdateServerResponse response = QueryLatestFirmwareVersion(latestVersion);

    if (response == UPDATE_SERVER_ERROR) {
        LogError("Error querying firmware version from server");
        return false;
    }

    if (response == UPDATE_SERVER_UNAVAILABLE) {
        LogWarning("Update server unavailable, using cached information");
        return false;
    }

    // Compare versions
    VersionComparisonResult comparison = CompareFirmwareVersions(currentVersion, latestVersion);

    if (comparison == VERSION_NEWER_AVAILABLE) {
        LogInfo("New firmware version available: %s (current: %s)", 
                latestVersion.ToString().c_str(), 
                currentVersion.ToString().c_str());
        updateAvailable = true;

        // Store latest version info for upgrade process
        StorePendingFirmwareInfo(latestVersion);
    }
    else if (comparison == VERSION_CURRENT) {
        LogInfo("Device firmware is up to date (version: %s)", currentVersion.ToString().c_str());
        // Mark current firmware as valid
        MarkFirmwareAsValid();
    }
    else if (comparison == VERSION_NEWER_INSTALLED) {
        LogWarning("Device has newer firmware than server reports: %s", 
                   currentVersion.ToString().c_str());
        // This could indicate development version or server issue
        MarkFirmwareAsValid();
    }

    // Disconnect from server to save power
    if (IsUpdateServerConnected()) {
        DisconnectFromUpdateServer();
    }

    return updateAvailable;
}

