    // This could involve writing to a display buffer, sending over serial,
    // or updating a GUI element depending on the embedded system

    // Clear any previous display content
    ClearDisplay();

    // Show header information
    DisplayText("ACTIVATION REQUIRED", 0, 0);

    // Display the activation code prominently
    DisplayText("Code: " + activationCode, 0, 20);

    // Display device identifier for reference
    DisplayText("Device: " + deviceId, 0, 40);

    // Show instruction for user
    DisplayText("Enter code in app to activate", 0, 60);

    // Update the display to show the new content
