    // Log the activation code display event
    LogEvent("Activation code displayed: " + activationCode);

    // Set LED indicator to show activation mode
    SetLEDStatus(LED_BLUE_BLINKING);

    // If the system has audio capability, beep to indicate state change
    if (HasAudioCapability()) {
        Beep(500, 1000); // 500ms duration, 1000Hz frequency
    }
}

void HandleToggleChatEvent() {
    // Check if device is currently speaking
    if (IsDeviceSpeaking()) {
        // Defer wake word handling until current audio task completes
        DeferWakeWordHandling();
        return;
    }

    // Update device state to listening mode
    SetDeviceState(DEVICE_STATE_LISTENING);

    // Encode the wake word for transmission
    WakeWordData wakeWordData = EncodeWakeWord();

    // Check if audio channel is open, open if necessary
    if (!IsAudioChannelOpen()) {
        OpenAudioChannel();
    }

    // Get current acoustic echo cancellation settings
    bool aecEnabled = GetAECSetting();

    // Update listening mode based on AEC settings
    if (aecEnabled) {
        SetListeningMode(LISTENING_MODE_AEC_ENABLED);
    } else {
        SetListeningMode(LISTENING_MODE_DEFAULT);
    }

    // Send wake word data to server
    SendWakeWordToServer(wakeWordData);

    // Start audio capture for subsequent speech
    StartAudioCapture();
}

void HandleStartListeningEvent()
{
    // Update device state to listening mode
    SetDeviceState(DEVICE_STATE_LISTENING);

    // Enable wake word detection
    AudioProcessing_EnableWakeWordDetection(true);

    // Enable voice processing for active listening
    AudioProcessing_EnableVoiceProcessing(true);

    // Update display to show listening status
    Display_UpdateStatus(DISPLAY_STATUS_LISTENING);

    // Update emotion to indicate active listening
    Display_UpdateEmotion(EMOTION_LISTENING);

    // Send start listening command to protocol manager
    ProtocolManager_SendCommand(PROTOCOL_CMD_START_LISTENING);

    // Enable microphone input
    AudioHardware_EnableMicrophone(true);

    // Start audio capture for voice processing
    AudioCapture_Start();

    // Log the event
    Logger_LogEvent(LOG_EVENT_START_LISTENING, LOG_LEVEL_INFO);
}

void HandleWakeWordDetectedEvent()
{
    // Log the wake word detection event
    LogSystemEvent("Wake word detected", LogLevel::INFO);

    // Close any active audio channels to prepare for voice interaction
    CloseActiveAudioChannel();

    // Prepare system for wake word response (e.g., listening mode)
    PrepareForVoiceInteraction();

    // Notify wake word detection subscribers/callbacks
    NotifyWakeWordDetected();

    // Ensure system state integrity during wake word handling
    UpdateSystemState(SystemState::WAKE_WORD_DETECTED);
}

void HandleStateChangedEvent()
{
    // Delay execution to allow system stabilization
    Delay(1000); // 1 second delay

    // Set device state to upgrading
    SetDeviceState(DEVICE_STATE_UPGRADING);

    // Display upgrade message to user
    DisplayMessage("Firmware upgrade in progress...");

    // Stop audio services during upgrade
    StopAudioServices();

    // Perform OTA upgrade with progress updates
    bool upgradeResult = false;
    int progress = 0;

    // Initialize OTA upgrade process
    if (InitializeOTAUpgrade())
    {
        // Perform the actual firmware download and installation
        while (progress < 100 && !IsOTAUpgradeCancelled())
        {
            progress = PerformOTAStep();

            // Update progress display
            UpdateProgressMessage("Upgrading... ", progress, "%");

            // Small delay between steps to prevent blocking
            Delay(50);
        }

        // Finalize the upgrade process
        upgradeResult = FinalizeOTAUpgrade();
    }

    if (upgradeResult)
    {
        // Upgrade successful - reboot device
        DisplayMessage("Upgrade complete. Rebooting...");
        Delay(2000); // Give user time to read message
        RebootDevice();
    }
    else
    {
        // Upgrade failed - restart audio services and alert user
        StartAudioServices();
        SetDeviceState(DEVICE_STATE_ERROR);
        DisplayErrorMessage("Firmware upgrade failed. Please try again.");
    }
}

bool UpgradeFirmware(const std::string& firmwarePath, const std::string& version)
{
    // Validate input parameters
    if (firmwarePath.empty() || version.empty()) {
        NotifyUI("Firmware upgrade failed: Invalid parameters");
        return false;
    }

    // Close any active audio channels to prevent conflicts during upgrade
    CloseActiveAudioChannels();

    // Update internal state to indicate upgrade in progress
    SetUpgradeStatus(true);

    // Notify UI about upgrade start
    NotifyUI("Starting firmware upgrade to version: " + version);

    // Validate firmware file integrity and compatibility
    if (!ValidateFirmwareFile(firmwarePath, version)) {
        NotifyUI("Firmware upgrade failed: Invalid firmware file");
        SetUpgradeStatus(false);
        return false;
    }

    // Perform the actual firmware upgrade
    bool upgradeResult = PerformFirmwareUpgrade(firmwarePath, version);

    if (upgradeResult) {
        // Update internal firmware version tracking
        mCurrentFirmwareVersion = version;

        // Save the new firmware version to persistent storage
        SaveFirmwareVersion(version);

        // Notify UI of successful upgrade
        NotifyUI("Firmware upgrade completed successfully to version: " + version);
    } else {
        // Notify UI of failed upgrade
        NotifyUI("Firmware upgrade failed: Upgrade process error");
    }

    // Reset upgrade status
    SetUpgradeStatus(false);

    // Reinitialize audio system after upgrade
    InitializeAudioSystem();

    return upgradeResult;
}

void WakeWordInvoke(const std::string &wakeWord) {
    // Log the wake word detection event
    ESP_LOGI(TAG, "Wake word detected: %s", wakeWord.c_str());

    // Check if the wake word engine is initialized and active
    if (!engine || !isRunning) {
        ESP_LOGW(TAG, "Wake word engine not ready");
        return;
    }

    // Stop audio capture temporarily to prevent interference
    if (audio_capture) {
        audio_capture->stop();
    }

    // Set wake word detected flag
    wakeWordDetected = true;

    // Store the detected wake word for further processing
    lastDetectedWakeWord = wakeWord;

    // Update detection timestamp
    lastDetectionTime = esp_timer_get_time() / 1000; // Convert to milliseconds

    // Trigger callback if registered
    if (wakeWordCallback) {
        wakeWordCallback(wakeWord);
    }

    // Notify any waiting threads/sleepers
    if (sleepHandle) {
        xSemaphoreGive(sleepHandle);
    }

    // Restart audio capture after brief delay
    if (audio_capture) {
        // Use timer to restart capture after processing delay
        esp_timer_start_once(restartTimer, RESTART_DELAY_US);
    }

    // Increment detection counter for statistics
    detectionCount++;

    // Handle state transition
    currentState = WAKE_WORD_DETECTED;
}

void SetAecMode(int AecMode)
{
    // Validate the AEC mode parameter
    if (AecMode < 0 || AecMode >= AEC_MODE_MAX) {
        return; // Invalid mode, ignore the request
    }

    // Check if the mode is already set to avoid unnecessary processing
    if (currentAecMode == AecMode) {
        return;
    }

    // Store the new AEC mode
    currentAecMode = AecMode;

    // Apply the AEC mode configuration based on the selected mode
    switch (AecMode) {
        case AEC_MODE_OFF:
            // Disable AEC processing
            aecEnable = false;
            aecAggressiveness = 0;
            break;

        case AEC_MODE_NORMAL:
            // Enable standard AEC with moderate settings
            aecEnable = true;
            aecAggressiveness = 1;
            aecDelayCompensation = DEFAULT_DELAY_COMPENSATION;
            break;

        case AEC_MODE_AGGRESSIVE:
            // Enable aggressive AEC for noisy environments
            aecEnable = true;
            aecAggressiveness = 3;
            aecNonLinearProcessing = true;
            break;

        case AEC_MODE_ADAPTIVE:
            // Enable adaptive AEC that adjusts parameters automatically
            aecEnable = true;
            aecAggressiveness = 2;
            aecAdaptiveMode = true;
            break;

        default:
            // Unknown mode, default to normal operation
            aecEnable = true;
            aecAggressiveness = 1;
            break;
    }

    // Update the AEC engine with new parameters
    UpdateAecEngine();

    // Optionally notify other modules about the mode change
    NotifyAecModeChange(AecMode);
}

bool InitializePartition()
{
    // Step 1: Check if partition exists and get its header
    if (!partition_base_ || partition_size_ == 0) {
        return false;
    }

    // Step 2: Validate partition header
    PartitionHeader* header = reinterpret_cast<PartitionHeader*>(partition_base_);

    // Check magic number to ensure this is a valid partition
    if (header->magic != ASSETS_PARTITION_MAGIC) {
        return false;
    }

    // Check if partition size is sufficient
    if (header->partition_size > partition_size_) {
        return false;
    }

    // Step 3: Verify checksum
    uint32_t calculated_checksum = CalculateChecksum(
        reinterpret_cast<uint8_t*>(partition_base_) + sizeof(PartitionHeader),
        header->data_size
    );

    if (calculated_checksum != header->checksum) {
        return false;
    }

    // Step 4: Map partition into memory (platform specific implementation)
    // This might involve setting up memory protection, caching, etc.
    if (!MapMemory(partition_base_, header->partition_size)) {
        return false;
    }

    // Step 5: Build asset index
    asset_count_ = 0;
    assets_.clear();

    // Parse asset directory starting after header
    uint8_t* data_ptr = reinterpret_cast<uint8_t*>(partition_base_) + sizeof(PartitionHeader);
    uint32_t offset = 0;

    while (offset < header->data_size && asset_count_ < MAX_ASSETS) {
        // Check if we have enough space for asset header
        if (offset + sizeof(AssetHeader) > header->data_size) {
            break;
        }

        AssetHeader* asset_header = reinterpret_cast<AssetHeader*>(data_ptr + offset);

        // Validate asset header
        if (asset_header->size == 0 || 
            offset + sizeof(AssetHeader) + asset_header->size > header->data_size) {
            break;
        }

        // Add asset to index
        AssetInfo asset_info;
        asset_info.id = asset_header->id;
        asset_info.size = asset_header->size;
        asset_info.offset = offset + sizeof(AssetHeader);
        asset_info.data_ptr = data_ptr + asset_info.offset;

        assets_[asset_count_] = asset_info;
        asset_ids_[asset_header->id] = asset_count_;
        asset_count_++;

        // Move to next asset (aligned to 4-byte boundary for efficiency)
        offset += sizeof(AssetHeader) + asset_header->size;
        offset = (offset + 3) & ~3; // Align to 4-byte boundary
    }

    // Step 6: Mark partition as initialized
    is_initialized_ = true;

    return true;
}

// Helper function for checksum calculation (example implementation)
uint32_t CalculateChecksum(uint8_t* data, uint32_t size)
{
    uint32_t checksum = 0;
    for (uint32_t i = 0; i < size; i++) {
        checksum += data[i];
    }
    return checksum;
}

