bool Assets::Apply() {
    try {
        // Load and parse the index.json configuration file
        std::ifstream configFile("index.json");
        if (!configFile.is_open()) {
            LogError("Failed to open index.json configuration file");
            return false;
        }

        json config;
        try {
            configFile >> config;
        } catch (const std::exception& e) {
            LogError("Failed to parse index.json: " + std::string(e.what()));
            return false;
        }

        // Validate asset version
        if (!config.contains("version")) {
            LogError("Missing version field in index.json");
            return false;
        }

        std::string version = config["version"];
        if (!IsVersionCompatible(version)) {
            LogError("Incompatible asset version: " + version);
            return false;
        }

        // Process speech recognition models
        if (config.contains("speech_models")) {
            auto& models = config["speech_models"];
            if (!models.is_array()) {
                LogError("speech_models should be an array");
                return false;
            }

            for (const auto& model : models) {
                if (!model.contains("path") || !model.contains("language")) {
                    LogError("Speech model missing required fields (path, language)");
                    return false;
                }

                std::string modelPath = model["path"];
                std::string language = model["language"];

                // Load and initialize speech recognition model
                if (!LoadSpeechModel(modelPath, language)) {
                    LogError("Failed to load speech model: " + modelPath);
                    return false;
                }
            }
        }

        // Process UI themes
        if (config.contains("ui_themes")) {
            auto& themes = config["ui_themes"];
            if (!themes.is_object()) {
                LogError("ui_themes should be an object");
                return false;
            }

            for (auto& [themeName, themeConfig] : themes.items()) {
                if (!themeConfig.contains("fonts") || !themeConfig.contains("emojis")) {
                    LogError("Theme " + themeName + " missing required fields (fonts, emojis)");
                    return false;
                }

                // Process fonts
                auto& fonts = themeConfig["fonts"];
                if (!fonts.is_array()) {
                    LogError("Fonts should be an array in theme: " + themeName);
                    return false;
                }

                std::vector<std::string> fontPaths;
                for (const auto& font : fonts) {
                    if (!font.is_string()) {
                        LogError("Font path should be a string in theme: " + themeName);
                        return false;
                    }
                    fontPaths.push_back(font.get<std::string>());
                }

                // Process emojis
                auto& emojis = themeConfig["emojis"];
                if (!emojis.is_string()) {
                    LogError("Emojis path should be a string in theme: " + themeName);
                    return false;
                }
                std::string emojiPath = emojis.get<std::string>();

                // Apply UI theme
                if (!ApplyUITheme(themeName, fontPaths, emojiPath)) {
                    LogError("Failed to apply UI theme: " + themeName);
                    return false;
                }
            }
        }

        // Update asset registry
        currentAssetVersion = version;
        lastAppliedTimestamp = std::chrono::system_clock::now();

        LogInfo("All assets successfully applied");
        return true;

    } catch (const std::exception& e) {
        LogError("Exception during asset application: " + std::string(e.what()));
        return false;
    } catch (...) {
        LogError("Unknown exception during asset application");
        return false;
    }
}

bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progressCallback) {
    // Initialize variables
    const size_t BUFFER_SIZE = 4096;
    uint8_t* buffer = new uint8_t[BUFFER_SIZE];
    size_t totalBytesReceived = 0;
    size_t bytesWrittenToFlash = 0;
    time_t startTime = time(nullptr);
    time_t lastProgressUpdate = startTime;

    // Get flash partition information
    size_t partitionSize = GetPartitionSize();
    size_t sectorSize = GetSectorSize();
    uintptr_t partitionBaseAddress = GetPartitionBaseAddress();

    try {
        // Initialize HTTP client
        HttpClient httpClient;
        HttpResponse response = httpClient.Get(url);

        if (!response.IsSuccessful()) {
            delete[] buffer;
            return false;
        }

        size_t contentLength = response.GetContentLength();

        // Validate content size against partition size
        if (contentLength == 0 || contentLength > partitionSize) {
            delete[] buffer;
            return false;
        }

        // Erase flash partition
        size_t sectorsToErase = (contentLength + sectorSize - 1) / sectorSize;
        for (size_t i = 0; i < sectorsToErase; i++) {
            uintptr_t sectorAddress = partitionBaseAddress + (i * sectorSize);
            if (!EraseSector(sectorAddress)) {
                delete[] buffer;
                return false;
            }
        }

        // Download and write data
        size_t bytesReceived = 0;
        size_t currentSector = 0;
        size_t offsetInSector = 0;

        while ((bytesReceived = response.ReadData(buffer, BUFFER_SIZE)) > 0) {
            totalBytesReceived += bytesReceived;

            // Write data to flash
            uintptr_t writeAddress = partitionBaseAddress + bytesWrittenToFlash;
            if (!WriteToFlash(writeAddress, buffer, bytesReceived)) {
                delete[] buffer;
                return false;
            }

            bytesWrittenToFlash += bytesReceived;

            // Update progress periodically
            time_t currentTime = time(nullptr);
            if (currentTime - lastProgressUpdate >= 1) { // Update every second
                int progressPercent = static_cast<int>((totalBytesReceived * 100) / contentLength);
                size_t elapsedTime = currentTime - startTime;
                size_t downloadSpeed = elapsedTime > 0 ? totalBytesReceived / elapsedTime : 0;

                if (progressCallback) {
                    progressCallback(progressPercent, downloadSpeed);
                }

                lastProgressUpdate = currentTime;
            }
        }

        // Final progress update
        if (progressCallback) {
            size_t finalElapsedTime = time(nullptr) - startTime;
            size_t finalSpeed = finalElapsedTime > 0 ? totalBytesReceived / finalElapsedTime : 0;
            progressCallback(100, finalSpeed);
        }

        delete[] buffer;
        return true;

    } catch (const std::exception& e) {
        if (buffer) {
            delete[] buffer;
        }
        return false;
    }
}

