bool IsValidTransition(DeviceState currentState, DeviceState targetState) const {
    // Allow all self-transitions as they maintain system stability
    if (currentState == targetState) {
        return true;
    }

    // Define valid state transitions based on typical embedded system patterns
    switch (currentState) {
        case DEVICE_STATE_UNINITIALIZED:
            // From uninitialized, typically only initialization is allowed
            return (targetState == DEVICE_STATE_INITIALIZING);

        case DEVICE_STATE_INITIALIZING:
            // From initializing, can go to ready or error states
            return (targetState == DEVICE_STATE_READY || 
                    targetState == DEVICE_STATE_ERROR);

        case DEVICE_STATE_READY:
            // From ready, can go to active, idle, or error states
            return (targetState == DEVICE_STATE_ACTIVE || 
                    targetState == DEVICE_STATE_IDLE ||
                    targetState == DEVICE_STATE_ERROR);

        case DEVICE_STATE_IDLE:
            // From idle, can resume to ready or go to error/shutdown
            return (targetState == DEVICE_STATE_READY || 
                    targetState == DEVICE_STATE_ERROR ||
                    targetState == DEVICE_STATE_SHUTDOWN);

        case DEVICE_STATE_ACTIVE:
            // From active, can go to idle, ready, or error states
            return (targetState == DEVICE_STATE_IDLE || 
                    targetState == DEVICE_STATE_READY ||
                    targetState == DEVICE_STATE_ERROR);

        case DEVICE_STATE_ERROR:
            // From error state, typically can only reset or shutdown
            return (targetState == DEVICE_STATE_RESET || 
                    targetState == DEVICE_STATE_SHUTDOWN);

        case DEVICE_STATE_RESET:
            // From reset, typically go back to initialization
            return (targetState == DEVICE_STATE_INITIALIZING);

        case DEVICE_STATE_SHUTDOWN:
            // From shutdown, typically only initialization is allowed
            return (targetState == DEVICE_STATE_INITIALIZING);

        default:
            // Unknown current state, transition not allowed
            return false;
    }
}

bool DeviceStateMachine::TransitionTo(DeviceState newState) {
    // Get current state
    DeviceState currentState = GetCurrentState();

    // Validate if transition is allowed
    if (!IsTransitionValid(currentState, newState)) {
        return false;
    }

    // Store previous state for notification
    DeviceState previousState = currentState;

    // Perform the state transition
    SetCurrentState(newState);

    // Notify all registered observers about the state change
    NotifyObservers(previousState, newState);

    return true;
}

