void McpServer::AddUserOnlyTools()
{
    // Register system information retrieval tool
    server_->AddCommandHandler("get_system_info", 
        [this](const Json::Value& request, Json::Value& response) {
            if (!CheckUserPermissions(request)) {
                response["error"] = "Insufficient permissions";
                return false;
            }

            try {
                SystemInfo info = GetSystemInformation();
                response["success"] = true;
                response["data"] = SerializeSystemInfo(info);
            } catch (const std::exception& e) {
                response["error"] = std::string("Failed to retrieve system info: ") + e.what();
                return false;
            }
            return true;
        });

    // Register device reboot tool
    server_->AddCommandHandler("reboot_device",
        [this](const Json::Value& request, Json::Value& response) {
            if (!CheckUserPermissions(request)) {
                response["error"] = "Insufficient permissions";
                return false;
            }

            // Schedule reboot in event loop for safety
            event_loop_->Post([this]() {
                PerformSafeReboot();
            });

            response["success"] = true;
            response["message"] = "Reboot scheduled";
            return true;
        });

    // Register firmware upgrade tool
    server_->AddCommandHandler("upgrade_firmware",
        [this](const Json::Value& request, Json::Value& response) {
            if (!CheckUserPermissions(request)) {
                response["error"] = "Insufficient permissions";
                return false;
            }

            if (!request.isMember("url") || !request["url"].isString()) {
                response["error"] = "Missing or invalid firmware URL";
                return false;
            }

            std::string firmware_url = request["url"].asString();

            // Schedule upgrade in event loop for safety
            event_loop_->Post([this, firmware_url]() {
                PerformFirmwareUpgrade(firmware_url);
            });

            response["success"] = true;
            response["message"] = "Firmware upgrade scheduled";
            return true;
        });

    // Register screen capture tool
    server_->AddCommandHandler("capture_screen",
        [this](const Json::Value& request, Json::Value& response) {
            if (!CheckUserPermissions(request)) {
                response["error"] = "Insufficient permissions";
                return false;
            }

            try {
                ScreenCapture capture = CaptureScreen();
                response["success"] = true;
                response["data"] = EncodeScreenCapture(capture);
                response["timestamp"] = GetCurrentTimestamp();
            } catch (const std::exception& e) {
                response["error"] = std::string("Screen capture failed: ") + e.what();
                return false;
            }
            return true;
        });

    // Register screen display tool
    server_->AddCommandHandler("display_screen",
        [this](const Json::Value& request, Json::Value& response) {
            if (!CheckUserPermissions(request)) {
                response["error"] = "Insufficient permissions";
                return false;
            }

            if (!request.isMember("data")) {
                response["error"] = "Missing screen data";
                return false;
            }

            try {
                ScreenCapture capture = DecodeScreenCapture(request["data"]);
                DisplayScreen(capture);
                response["success"] = true;
                response["message"] = "Screen displayed successfully";
            } catch (const std::exception& e) {
                response["error"] = std::string("Display failed: ") + e.what();
                return false;
            }
            return true;
        });
}

void McpServer::ParseMessage(const cJSON* message) {
    // Validate input message
    if (!message || message->type != cJSON_Object) {
        SendErrorResponse(nullptr, -32600, "Invalid Request");
        return;
    }

    // Extract required JSON-RPC fields
    cJSON* jsonrpc = cJSON_GetObjectItem(message, "jsonrpc");
    cJSON* method = cJSON_GetObjectItem(message, "method");
    cJSON* id = cJSON_GetObjectItem(message, "id");

    // Validate JSON-RPC version
    if (!jsonrpc || jsonrpc->type != cJSON_String || strcmp(jsonrpc->valuestring, "2.0") != 0) {
        SendErrorResponse(id, -32600, "Invalid Request");
        return;
    }

    // Check if this is a response (has result or error) rather than a request
    cJSON* result = cJSON_GetObjectItem(message, "result");
    cJSON* error = cJSON_GetObjectItem(message, "error");

    if (result || error) {
        // This is a response message, not a request - handle accordingly
        HandleResponse(message);
        return;
    }

    // Validate method field for requests
    if (!method || method->type != cJSON_String) {
        SendErrorResponse(id, -32600, "Invalid Request");
        return;
    }

    // Extract params if present
    cJSON* params = cJSON_GetObjectItem(message, "params");

    // Route based on method
    const char* method_name = method->valuestring;

    if (strcmp(method_name, "initialize") == 0) {
        HandleInitializeRequest(id, params);
    } else if (strcmp(method_name, "tools/list") == 0) {
        HandleToolsListRequest(id, params);
    } else if (strcmp(method_name, "tools/call") == 0) {
        HandleToolsCallRequest(id, params);
    } else {
        // Unknown method
        SendErrorResponse(id, -32601, "Method not found");
    }
}

private:
void McpServer::HandleInitializeRequest(cJSON* id, cJSON* params) {
    // Validate params structure
    if (!params || params->type != cJSON_Object) {
        SendErrorResponse(id, -32602, "Invalid params");
        return;
    }

    // Extract capabilities from params
    cJSON* capabilities = cJSON_GetObjectItem(params, "capabilities");
    if (capabilities && capabilities->type == cJSON_Object) {
        ParseCapabilities(capabilities);
    }

    // Create initialize response
    cJSON* response = cJSON_CreateObject();
    cJSON_AddStringToObject(response, "jsonrpc", "2.0");
    cJSON_AddItemToObject(response, "id", cJSON_Duplicate(id, 1));

    cJSON* result = cJSON_CreateObject();
    cJSON_AddStringToObject(result, "status", "success");
    cJSON_AddItemToObject(response, "result", result);

    SendResponse(response);
    cJSON_Delete(response);
}

void McpServer::HandleToolsListRequest(cJSON* id, cJSON* params) {
    // Tools list may not require parameters, but validate if provided
    if (params && params->type != cJSON_Object && params->type != cJSON_NULL) {
        SendErrorResponse(id, -32602, "Invalid params");
        return;
    }

    // Get list of available tools
    std::vector<ToolInfo> tools = GetAvailableTools();

    // Create response
    cJSON* response = cJSON_CreateObject();
    cJSON_AddStringToObject(response, "jsonrpc", "2.0");
    cJSON_AddItemToObject(response, "id", cJSON_Duplicate(id, 1));

    cJSON* result = cJSON_CreateArray();
    for (const auto& tool : tools) {
        cJSON* tool_obj = cJSON_CreateObject();
        cJSON_AddStringToObject(tool_obj, "name", tool.name.c_str());
        cJSON_AddStringToObject(tool_obj, "description", tool.description.c_str());
        cJSON_AddItemToArray(result, tool_obj);
    }

    cJSON_AddItemToObject(response, "result", result);
    SendResponse(response);
    cJSON_Delete(response);
}

void McpServer::HandleToolsCallRequest(cJSON* id, cJSON* params) {
    // Validate params structure
    if (!params || params->type != cJSON_Object) {
        SendErrorResponse(id, -32602, "Invalid params");
        return;
    }

    // Extract tool name and arguments
    cJSON* tool_name = cJSON_GetObjectItem(params, "name");
    cJSON* arguments = cJSON_GetObjectItem(params, "arguments");

    if (!tool_name || tool_name->type != cJSON_String) {
        SendErrorResponse(id, -32602, "Missing or invalid tool name");
        return;
    }

    // Execute the tool
    ToolResult result = ExecuteTool(tool_name->valuestring, arguments);

    // Create response
    cJSON* response = cJSON_CreateObject();
    cJSON_AddStringToObject(response, "jsonrpc", "2.0");
    cJSON_AddItemToObject(response, "id", cJSON_Duplicate(id, 1));

    if (result.success) {
        cJSON* result_obj = cJSON_CreateObject();
        cJSON_AddStringToObject(result_obj, "output", result.output.c_str());
        cJSON_AddItemToObject(response, "result", result_obj);
    } else {
        SendErrorResponse(id, -32000, result.error_message.c_str());
        cJSON_Delete(response);
        return;
    }

    SendResponse(response);
    cJSON_Delete(response);
}

void McpServer::SendErrorResponse(cJSON* id, int code, const char* message) {
    cJSON* response = cJSON_CreateObject();
    cJSON_AddStringToObject(response, "jsonrpc", "2.0");

    if (id) {
        cJSON_AddItemToObject(response, "id", cJSON_Duplicate(id, 1));
    } else {
        cJSON_AddNullToObject(response, "id");
    }

    cJSON* error = cJSON_CreateObject();
    cJSON_AddNumberToObject(error, "code", code);
    cJSON_AddStringToObject(error, "message", message);
    cJSON_AddItemToObject(response, "error", error);

    SendResponse(response);
    cJSON_Delete(response);
}

