std::string GetToolsList(int limit, const std::string& cursor, bool includeMetadata) {
    try {
        // Initialize response structure
        json response;
        std::vector<Tool> filteredTools;

        // Prepare request to MCP server
        HttpClient httpClient("https://mcp-server/api");
        HttpRequest request;
        request.setMethod("GET");
        request.setEndpoint("/tools");

        // Add pagination parameters
        request.addQueryParam("limit", std::to_string(limit));
        if (!cursor.empty()) {
            request.addQueryParam("cursor", cursor);
        }

        // Add authentication headers
        std::string authToken = getCurrentUserToken();
        request.addHeader("Authorization", "Bearer " + authToken);
        request.addHeader("Content-Type", "application/json");

        // Make request to MCP server
        HttpResponse serverResponse = httpClient.sendRequest(request);

        // Check if request was successful
        if (serverResponse.getStatusCode() != 200) {
            throw std::runtime_error("Failed to retrieve tools from server: " + 
                                   std::to_string(serverResponse.getStatusCode()));
        }

        // Parse server response
        json serverData = json::parse(serverResponse.getBody());

        // Extract tools list
        std::vector<Tool> allTools;
        for (const auto& toolJson : serverData["tools"]) {
            Tool tool;
            tool.id = toolJson["id"];
            tool.name = toolJson["name"];
            tool.description = toolJson["description"];
            tool.size = toolJson["size"];
            tool.permissions = toolJson["permissions"];
            allTools.push_back(tool);
        }

        // Filter tools based on user permissions
        std::string currentUserRole = getCurrentUserRole();
        for (const auto& tool : allTools) {
            if (hasPermission(currentUserRole, tool.permissions)) {
                // Check payload size constraints
                if (tool.size <= getMaxPayloadSize()) {
                    filteredTools.push_back(tool);
                } else {
                    // Log size constraint violation
                    logError("Tool " + tool.id + " exceeds payload size limit");
                    if (filteredTools.empty()) {
                        response["error"] = "All available tools exceed payload size limits";
                        return response.dump();
                    }
                }
            }
        }

        // Build response with pagination info
        response["tools"] = json::array();
        for (const auto& tool : filteredTools) {
            json toolJson;
            toolJson["id"] = tool.id;
            toolJson["name"] = tool.name;
            toolJson["description"] = tool.description;

            if (includeMetadata) {
                toolJson["size"] = tool.size;
                toolJson["permissions"] = tool.permissions;
            }

            response["tools"].push_back(toolJson);
        }

        // Add pagination information
        response["pagination"]["limit"] = limit;
        if (serverData.contains("next_cursor")) {
            response["pagination"]["next_cursor"] = serverData["next_cursor"];
        }
        if (serverData.contains("prev_cursor")) {
            response["pagination"]["prev_cursor"] = serverData["prev_cursor"];
        }

        response["pagination"]["total_count"] = filteredTools.size();

        return response.dump();

    } catch (const json::exception& e) {
        json errorResponse;
        errorResponse["error"] = "Invalid response format from server";
        errorResponse["details"] = e.what();
        return errorResponse.dump();
    } catch (const std::exception& e) {
        json errorResponse;
        errorResponse["error"] = "Failed to retrieve tools";
        errorResponse["details"] = e.what();
        return errorResponse.dump();
    }
}

