std::string Ota::GetActivationPayload() {
    // Get the device serial number
    std::string serialNumber = GetDeviceSerialNumber();

    // Check if serial number is available
    if (serialNumber.empty()) {
        // Return empty JSON object if serial number is not available
        return "{}";
    }

    // Get the challenge string
    std::string challenge = GetChallengeString();

    // Create data to be signed (serial + challenge)
    std::string dataToSign = serialNumber + challenge;

    // Compute HMAC-SHA256 signature using hardware-backed key
    std::string signature = ComputeHMACSHA256(dataToSign);

    // Create JSON payload
    std::string jsonPayload = "{";
    jsonPayload += "\"serial\":\"" + serialNumber + "\",";
    jsonPayload += "\"challenge\":\"" + challenge + "\",";
    jsonPayload += "\"signature\":\"" + signature + "\"";
    jsonPayload += "}";

    return jsonPayload;
}

int Ota::Activate()
{
    // Construct the activation URL
    std::string activationUrl = m_baseUrl + "/api/v1/activate";

    // Prepare the activation payload
    std::string payload = "{"
                         "\"device_id\":\"" + m_deviceId + "\","
                         "\"firmware_version\":\"" + m_firmwareVersion + "\","
                         "\"activation_token\":\"" + m_activationToken + "\""
                         "}";

    // Set HTTP headers
    HttpHeaders headers;
    headers["Content-Type"] = "application/json";
    headers["Accept"] = "application/json";

    // Send HTTP POST request
    HttpResponse response;
    HttpResult result = HttpClient::Post(activationUrl, payload, headers, response);

    // Check if HTTP request was successful
    if (result != HTTP_SUCCESS) {
        LogError("Failed to send activation request: %d", result);
        return OTA_ERROR_NETWORK;
    }

    // Handle server response based on HTTP status code
    switch (response.statusCode) {
        case 200: // OK - Activation successful
            {
                // Parse response to verify activation
                JsonParser parser;
                JsonObject jsonResp;
                if (parser.Parse(response.body, jsonResp) == PARSE_SUCCESS) {
                    std::string status;
                    if (jsonResp.GetString("status", status) == PARSE_SUCCESS) {
                        if (status == "activated") {
                            LogInfo("OTA activation successful");
                            m_isActivated = true;
                            return OTA_SUCCESS;
                        } else {
                            LogError("Activation failed: %s", status.c_str());
                            return OTA_ERROR_ACTIVATION_FAILED;
                        }
                    }
                }
                LogWarning("Could not parse activation response, but HTTP 200 received");
                m_isActivated = true;
                return OTA_SUCCESS;
            }
            break;

        case 400: // Bad Request
            LogError("Bad request: %s", response.body.c_str());
            return OTA_ERROR_BAD_REQUEST;

        case 401: // Unauthorized
            LogError("Unauthorized access to activation endpoint");
            return OTA_ERROR_UNAUTHORIZED;

        case 404: // Not Found
            LogError("Activation endpoint not found");
            return OTA_ERROR_ENDPOINT_NOT_FOUND;

        case 409: // Conflict - already activated or invalid state
            LogError("Conflict: %s", response.body.c_str());
            return OTA_ERROR_CONFLICT;

        case 500: // Internal Server Error
            LogError("Server internal error during activation");
            return OTA_ERROR_SERVER_ERROR;

        default:
            LogError("Unexpected HTTP status code: %d", response.statusCode);
            return OTA_ERROR_UNKNOWN;
    }
}

void PrintTaskCpuUsage(TickType_t xDelayTime)
{
    // Buffer to store task runtime statistics (before and after)
    char pcWriteBuffer[2048];
    char pcWriteBufferAfter[2048];

    // Variables to track task count and detect changes
    UBaseType_t uxTaskCountBefore, uxTaskCountAfter;

    // Get initial task list and runtime statistics
    memset(pcWriteBuffer, 0, sizeof(pcWriteBuffer));
    vTaskList(pcWriteBuffer);

    // Count initial tasks by parsing the buffer
    uxTaskCountBefore = 0;
    char* ptr = pcWriteBuffer;
    while(*ptr != '\0') {
        if(*ptr == '\n') uxTaskCountBefore++;
        ptr++;
    }
    if(strlen(pcWriteBuffer) > 0 && pcWriteBuffer[strlen(pcWriteBuffer)-1] != '\n') {
        uxTaskCountBefore++; // Account for last line without newline
    }

    // Wait for the specified time interval
    vTaskDelay(xDelayTime);

    // Get task list and runtime statistics after delay
    memset(pcWriteBufferAfter, 0, sizeof(pcWriteBufferAfter));
    vTaskList(pcWriteBufferAfter);

    // Count final tasks
    uxTaskCountAfter = 0;
    ptr = pcWriteBufferAfter;
    while(*ptr != '\0') {
        if(*ptr == '\n') uxTaskCountAfter++;
        ptr++;
    }
    if(strlen(pcWriteBufferAfter) > 0 && pcWriteBufferAfter[strlen(pcWriteBufferAfter)-1] != '\n') {
        uxTaskCountAfter++; // Account for last line without newline
    }

    // Print header
    printf("\n=== Task CPU Usage Report ===\n");
    printf("Measurement Duration: %lu ticks\n", (unsigned long)xDelayTime);

    // Check for task creation/deletion
    if(uxTaskCountAfter > uxTaskCountBefore) {
        printf("WARNING: %lu task(s) created during measurement\n", 
               (unsigned long)(uxTaskCountAfter - uxTaskCountBefore));
    } else if(uxTaskCountAfter < uxTaskCountBefore) {
        printf("WARNING: %lu task(s) deleted during measurement\n", 
               (unsigned long)(uxTaskCountBefore - uxTaskCountAfter));
    }

    // Parse and calculate CPU usage for each task
    // Note: This simplified version assumes vTaskGetRunTimeStats is available
    // In a real implementation, you would parse the task lists and calculate differences

    char runtimeStatsBuffer[2048];
    memset(runtimeStatsBuffer, 0, sizeof(runtimeStatsBuffer));

    // If runtime statistics are enabled, get detailed stats
    #if(configGENERATE_RUN_TIME_STATS == 1)
        vTaskGetRunTimeStats(runtimeStatsBuffer);
        printf("\nTask Name\t\tAbs Time\t\t%% Time\n");
        printf("**********************************************\n");
        printf("%s", runtimeStatsBuffer);
    #else
        printf("\nRuntime statistics not enabled in configuration.\n");
        printf("Enable configGENERATE_RUN_TIME_STATS to see detailed CPU usage.\n");
    #endif

    // Display current task list
    printf("\nCurrent Active Tasks:\n");
    printf("**********************************************\n");
    printf("Task Name\t\tState\tPriority\tStack\tTask Number\n");
    printf("%s", pcWriteBufferAfter);

    printf("==============================================\n\n");
}

bool AudioService::Initialize(AudioCodec* codec) {
    // Validate input parameter
    if (!codec) {
        return false;
    }

    // Store codec reference
    audio_codec_ = codec;

    // Configure the audio codec
    if (!audio_codec_->Configure(kDefaultSampleRate, kDefaultChannels, kDefaultBitDepth)) {
        return false;
    }

    // Initialize Opus encoder wrapper
    opus_encoder_ = std::make_unique<OpusEncoderWrapper>();
    if (!opus_encoder_->Initialize(kDefaultSampleRate, kDefaultChannels, OPUS_APPLICATION_VOIP)) {
        return false;
    }

    // Initialize Opus decoder wrapper
    opus_decoder_ = std::make_unique<OpusDecoderWrapper>();
    if (!opus_decoder_->Initialize(kDefaultSampleRate, kDefaultChannels)) {
        return false;
    }

    // Set up resamplers for input audio
    input_resampler_ = std::make_unique<AudioResampler>();
    if (!input_resampler_->Initialize(codec->GetInputSampleRate(), kProcessingSampleRate)) {
        return false;
    }

    output_resampler_ = std::make_unique<AudioResampler>();
    if (!output_resampler_->Initialize(kProcessingSampleRate, codec->GetOutputSampleRate())) {
        return false;
    }

    // Initialize audio processor for VAD
    audio_processor_ = std::make_unique<AudioProcessor>();
    if (!audio_processor_->Initialize(kProcessingSampleRate, kDefaultChannels)) {
        return false;
    }

    // Configure VAD parameters
    audio_processor_->SetVadMode(true);
    audio_processor_->SetVadThreshold(kDefaultVadThreshold);

    // Set up power state management timer
    power_timer_ = std::make_unique<Timer>();
    if (!power_timer_->Initialize(kPowerCheckIntervalMs, [this]() {
        this->UpdatePowerState();
    })) {
        return false;
    }

    // Initialize callback mechanisms
    audio_input_callback_ = nullptr;
    audio_output_callback_ = nullptr;
    vad_callback_ = nullptr;

    // Set initial power state
    current_power_state_ = PowerState::kActive;
    last_audio_activity_time_ = GetCurrentTimeMs();

    // Start the power management timer
    power_timer_->Start();

    // Mark service as initialized
    is_initialized_ = true;

    return true;
}

bool AudioService::Start() {
    // Clear all event flags to ensure clean startup state
    audioEventFlags.clear();

    // Start the periodic power timer for audio processing
    if (!powerTimer.start(kPowerTimerIntervalMs)) {
        return false;
    }

    // Determine task configuration based on audio processing enablement
    TaskPriority priority = isAudioProcessingEnabled() ? 
                           TaskPriority::HIGH : TaskPriority::NORMAL;
    CoreAffinity affinity = isAudioProcessingEnabled() ? 
                           CoreAffinity::DEDICATED_CORE : CoreAffinity::ANY_CORE;

    // Create audio input processing task
    audioInputTask = TaskManager::createTask(
        "AudioInput",
        [this]() { this->audioInputHandler(); },
        kAudioInputStackSize,
        priority,
        affinity
    );

    if (!audioInputTask.isValid()) {
        powerTimer.stop();
        return false;
    }

    // Create audio output processing task
    audioOutputTask = TaskManager::createTask(
        "AudioOutput", 
        [this]() { this->audioOutputHandler(); },
        kAudioOutputStackSize,
        priority,
        affinity
    );

    if (!audioOutputTask.isValid()) {
        audioInputTask.destroy();
        powerTimer.stop();
        return false;
    }

    // Create Opus codec processing task
    opusCodecTask = TaskManager::createTask(
        "OpusCodec",
        [this]() { this->opusCodecHandler(); },
        kOpusCodecStackSize,
        priority,
        affinity
    );

    if (!opusCodecTask.isValid()) {
        audioInputTask.destroy();
        audioOutputTask.destroy();
        powerTimer.stop();
        return false;
    }

    // Set real-time scheduling parameters for critical audio tasks
    if (isAudioProcessingEnabled()) {
        audioInputTask.setRealTime(true);
        audioOutputTask.setRealTime(true);
        opusCodecTask.setRealTime(true);
    }

    // Mark audio service as started
    isStarted = true;

    return true;
}

bool ReadAudioData(std::vector<int16_t>& audioBuffer, int targetSampleRate, int channels)
{
    // Power management - enable codec for capture
    static bool codecEnabled = false;
    if (!codecEnabled) {
        EnableAudioCodec(true);
        codecEnabled = true;
    }

    // Get current audio configuration
    static int currentSampleRate = GetAudioCodecSampleRate();
    static int currentChannels = GetAudioCodecChannels();

    // Clear output buffer
    audioBuffer.clear();

    // Determine how many samples to read based on target requirements
    const int baseSamplesPerChannel = 1024; // Base chunk size
    int totalSamplesToRead = baseSamplesPerChannel * channels;

    // Temporary buffer for raw audio data
    std::vector<int16_t> rawAudioData(totalSamplesToRead);

    // Read raw audio data from microphone/codec
    int samplesRead = ReadRawAudioSamples(rawAudioData.data(), totalSamplesToRead);

    if (samplesRead <= 0) {
        // No data available, manage power saving
        static int idleCount = 0;
        idleCount++;

        // Enable power saving after prolonged inactivity
        if (idleCount > 100) {
            EnableAudioCodec(false);
            codecEnabled = false;
            idleCount = 0;
        }

        return false;
    }

    // Reset idle counter since we have data
    static int idleCount = 0;
    idleCount = 0;

    // Handle sample rate conversion if needed
    if (currentSampleRate != targetSampleRate) {
        std::vector<int16_t> resampledData;
        ResampleAudioData(rawAudioData, samplesRead, currentSampleRate, targetSampleRate, channels, resampledData);
        audioBuffer = std::move(resampledData);
    } else {
        // No resampling needed, use raw data directly
        audioBuffer = std::move(rawAudioData);
        audioBuffer.resize(samplesRead);
    }

    // Handle channel format conversion if needed
    if (currentChannels != channels) {
        std::vector<int16_t> channelConvertedData;
        ConvertChannelFormat(audioBuffer, currentChannels, channels, channelConvertedData);
        audioBuffer = std::move(channelConvertedData);
    }

    // Update statistics
    static AudioStats stats;
    stats.totalSamplesCaptured += audioBuffer.size();
    stats.captureCalls++;
    UpdateCaptureTimestamp();

    // Debug information
#ifdef DEBUG_AUDIO_CAPTURE
    DebugLogAudioData(audioBuffer.data(), audioBuffer.size(), targetSampleRate, channels);
#endif

    // Validate output
    if (audioBuffer.empty()) {
        return false;
    }

    return true;
}

