void ResampleAudioData(const std::vector<int16_t>& input, int inputSize, 
                      int inputRate, int outputRate, int channels,
                      std::vector<int16_t>& output) {
    // Implement sample rate conversion algorithm
    // Could use linear interpolation, sinc interpolation, etc.
    // Simplified implementation:
    float ratio = static_cast<float>(inputRate) / static_cast<float>(outputRate);
    int outputSize = static_cast<int>(inputSize / ratio);
    output.resize(outputSize);

    for (int i = 0; i < outputSize; i++) {
        int srcIndex = static_cast<int>(i * ratio);
        if (srcIndex < inputSize) {
            output[i] = input[srcIndex];
        } else {
            output[i] = 0;
        }
    }
}

void ConvertChannelFormat(const std::vector<int16_t>& input, int inputChannels, 
                         int outputChannels, std::vector<int16_t>& output) {
    // Convert between mono and stereo formats
    if (inputChannels == 1 && outputChannels == 2) {
        // Mono to stereo: duplicate channels
        output.resize(input.size() * 2);
        for (size_t i = 0; i < input.size(); i++) {
            output[i * 2] = input[i];
            output[i * 2 + 1] = input[i];
        }
    } else if (inputChannels == 2 && outputChannels == 1) {
        // Stereo to mono: average channels
        output.resize(input.size() / 2);
        for (size_t i = 0; i < output.size(); i++) {
            int left = input[i * 2];
            int right = input[i * 2 + 1];
            output[i] = static_cast<int16_t>((left + right) / 2);
        }
    }
}

