void AudioInputTask() {
    // Audio frame buffer
    int16_t audio_buffer[AUDIO_FRAME_SIZE];
    AudioState current_state;

    // Initialize audio hardware
    audio_init();

    // Main processing loop
    while (1) {
        // Check for task termination
        if (task_should_terminate()) {
            break;
        }

        // Get current system state
        current_state = get_audio_system_state();

        // Capture audio frame from microphone
        if (audio_read_frame(audio_buffer, AUDIO_FRAME_SIZE) != AUDIO_SUCCESS) {
            // Handle audio capture error
            handle_audio_error();
            continue;
        }

        // Route audio based on current state
        switch (current_state) {
            case AUDIO_TEST:
                // Route to audio testing path
                audio_test_process(audio_buffer, AUDIO_FRAME_SIZE);
                break;

            case WAKE_WORD_DETECT:
                // Route to wake word detection engine
                wake_word_detect_process(audio_buffer, AUDIO_FRAME_SIZE);
                break;

            case GENERAL_PROCESSING:
                // Route to general audio processing
                general_audio_process(audio_buffer, AUDIO_FRAME_SIZE);
                break;

            default:
                // Default processing or error handling
                default_audio_process(audio_buffer, AUDIO_FRAME_SIZE);
                break;
        }

        // Optional: Add timing control for consistent sampling
        task_yield(); // Yield to other tasks if needed
    }

    // Cleanup resources
    audio_deinit();
}

void AudioOutputTask()
{
    // Initialize audio output task variables
    bool audioOutputEnabled = false;
    uint32_t processedSamples = 0;
    uint32_t droppedFrames = 0;
    uint32_t totalPlaybackTime = 0;

    // Main task loop - runs until service is stopped
    while (!serviceStopped) 
    {
        // Check if there's queued audio data to process
        if (!audioQueue.isEmpty()) 
        {
            // Enable audio output if not already enabled
            if (!audioOutputEnabled) 
            {
                enableAudioOutput();
                audioOutputEnabled = true;
            }

            // Retrieve audio data from queue
            AudioData audioData = audioQueue.dequeue();

            // Process audio data (decoding, format conversion, etc.)
            if (processAudioData(audioData)) 
            {
                // Send processed audio data to codec for playback
                if (sendToAudioCodec(audioData)) 
                {
                    // Update playback statistics
                    processedSamples += audioData.sampleCount;
                    totalPlaybackTime += audioData.durationMs;

                    // Record timestamp for AEC if enabled
                    if (aecEnabled) 
                    {
                        recordAecTimestamp(audioData.timestamp);
                    }
                } 
                else 
                {
                    // Handle codec send failure
                    droppedFrames++;
                    handleError(AUDIO_CODEC_SEND_ERROR);
                }
            } 
            else 
            {
                // Handle audio processing failure
                droppedFrames++;
                handleError(AUDIO_PROCESSING_ERROR);
            }
        } 
        else 
        {
            // No audio data available - disable output if previously enabled
            if (audioOutputEnabled) 
            {
                // Only disable after a small delay to handle brief gaps
                if (shouldDisableAudioOutput()) 
                {
                    disableAudioOutput();
                    audioOutputEnabled = false;
                }
            }

            // Update statistics even when no data is playing
            updatePlaybackStatistics(processedSamples, droppedFrames, totalPlaybackTime);
        }

        // Handle any pending control commands
        processControlCommands();

        // Yield to other tasks or sleep briefly to prevent busy waiting
        taskYieldOrSleep(AUDIO_TASK_SLEEP_MS);
    }

    // Cleanup when service is stopping
    if (audioOutputEnabled) 
    {
        disableAudioOutput();
    }

    // Final statistics update
    updatePlaybackStatistics(processedSamples, droppedFrames, totalPlaybackTime);

    // Clean up resources
    cleanupAudioResources();
}

void AudioService::OpusCodecTask()
{
    // Initialize Opus encoder and decoder
    OpusEncoder* encoder = opus_encoder_create(SAMPLE_RATE, CHANNELS, OPUS_APPLICATION_VOIP, nullptr);
    OpusDecoder* decoder = opus_decoder_create(SAMPLE_RATE, CHANNELS, nullptr);

    // Set encoder parameters
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(BITRATE));
    opus_encoder_ctl(encoder, OPUS_SET_VBR(1));
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(10));

    // Processing loop
    while (m_running)
    {
        // Check for PCM data to encode
        if (!m_pcmInputQueue.empty())
        {
            // Get PCM data from input queue
            AudioBuffer pcmData = m_pcmInputQueue.front();
            m_pcmInputQueue.pop_front();

            // Check queue limits to prevent overflow
            if (m_encodedOutputQueue.size() < MAX_QUEUE_SIZE)
            {
                // Allocate buffer for encoded data
                unsigned char encodedBuffer[MAX_PACKET_SIZE];

                // Encode PCM to Opus
                int encodedBytes = opus_encode(encoder, 
                                             reinterpret_cast<opus_int16*>(pcmData.data()), 
                                             FRAME_SIZE, 
                                             encodedBuffer, 
                                             MAX_PACKET_SIZE);

                if (encodedBytes > 0)
                {
                    // Create encoded packet
                    EncodedPacket packet;
                    packet.setData(encodedBuffer, encodedBytes);
                    packet.setTimestamp(pcmData.timestamp());

                    // Add to output queue
                    m_encodedOutputQueue.push_back(packet);

                    // Signal that encoded data is available
                    m_encodedDataAvailable.notify_one();
                }
                else
                {
                    // Handle encoding error
                    LOG_ERROR("Opus encoding failed with error: %d", encodedBytes);
                }
            }
            else
            {
                // Queue limit exceeded, drop oldest data
                LOG_WARNING("Encoded output queue full, dropping data");
            }
        }

        // Check for Opus data to decode
        if (!m_opusInputQueue.empty())
        {
            // Get Opus data from input queue
            EncodedPacket opusPacket = m_opusInputQueue.front();
            m_opusInputQueue.pop_front();

            // Check queue limits to prevent overflow
            if (m_decodedOutputQueue.size() < MAX_QUEUE_SIZE)
            {
                // Allocate buffer for decoded PCM data
                opus_int16 decodedBuffer[FRAME_SIZE * CHANNELS];

                // Decode Opus to PCM
                int decodedSamples = opus_decode(decoder,
                                               opusPacket.data(),
                                               opusPacket.size(),
                                               decodedBuffer,
                                               FRAME_SIZE,
                                               0);

                if (decodedSamples > 0)
                {
                    // Create PCM buffer
                    AudioBuffer pcmBuffer;
                    pcmBuffer.setData(reinterpret_cast<char*>(decodedBuffer), 
                                    decodedSamples * CHANNELS * sizeof(opus_int16));
                    pcmBuffer.setTimestamp(opusPacket.timestamp());

                    // Perform sample rate conversion if needed
                    AudioBuffer convertedBuffer = performSampleRateConversion(pcmBuffer);

                    // Add to output queue
                    m_decodedOutputQueue.push_back(convertedBuffer);

                    // Signal that decoded data is available
                    m_decodedDataAvailable.notify_one();
                }
                else
                {
                    // Handle decoding error
                    LOG_ERROR("Opus decoding failed with error: %d", decodedSamples);
                }
            }
            else
            {
                // Queue limit exceeded, drop oldest data
                LOG_WARNING("Decoded output queue full, dropping data");
            }
        }

        // Handle sample rate conversion for any remaining buffers
        processSampleRateConversions();

        // Yield to other tasks or sleep briefly to prevent busy waiting
        std::this_thread::sleep_for(std::chrono::milliseconds(1));
    }

    // Cleanup resources
    opus_encoder_destroy(encoder);
    opus_decoder_destroy(decoder);
}

void PushTaskToEncodeQueue(AudioTaskType task_type, std::vector<int16_t>&& audio_data) {
    std::unique_lock<std::mutex> lock(queue_mutex_);

    // Wait until there's space in the queue
    while (encode_queue_.size() >= MAX_QUEUE_SIZE) {
        queue_not_full_cv_.wait(lock);
    }

    // Create the audio task
    AudioTask task;
    task.type = task_type;
    task.audio_data = std::move(audio_data);

    // If this is an encode-to-send task, try to get a timestamp
    if (task_type == kAudioTaskTypeEncodeToSendQueue) {
        if (!timestamp_queue_.empty()) {
            task.timestamp = timestamp_queue_.front();
            timestamp_queue_.pop();
        } else {
            task.timestamp = 0; // or some default value
        }
    }

    // Add the task to the encode queue
    encode_queue_.push(std::move(task));

    // Notify waiting consumers that a new task is available
    queue_not_empty_cv_.notify_one();
}

void EnableWakeWordDetection(bool enable) {
    static bool isInitialized = false;
    static bool isEnabled = false;

    if (enable) {
        // Enable wake word detection
        if (!isInitialized) {
            // Initialize wake word detection system
            InitializeWakeWordDetection();
            isInitialized = true;
        }

        // Start detection process if not already enabled
        if (!isEnabled) {
            StartWakeWordDetection();
            SetWakeWordEventFlag();
            isEnabled = true;
        }
    } else {
        // Disable wake word detection
        if (isEnabled) {
            StopWakeWordDetection();
            ClearWakeWordEventFlag();
            isEnabled = false;
        }
    }
}

bool AudioService::PlaySound(const std::string_view& filename) {
    // Enable audio output if disabled
    if (!audioOutputEnabled) {
        if (!EnableAudioOutput()) {
            return false;
        }
    }

    // Open the OGG file
    FILE* file = fopen(std::string(filename).c_str(), "rb");
    if (!file) {
        return false;
    }

    // Initialize OGG stream
    ogg_sync_state syncState;
    ogg_stream_state streamState;
    ogg_page page;
    ogg_packet packet;

    ogg_sync_init(&syncState);

    OpusDecoder* opusDecoder = nullptr;
    int sampleRate = 48000; // Default Opus sample rate
    int channels = 2;       // Default stereo
    bool headerParsed = false;

    bool success = true;
    char* buffer;
    int bytes;

    while (success) {
        // Read data into OGG sync buffer
        buffer = ogg_sync_buffer(&syncState, 4096);
        bytes = fread(buffer, 1, 4096, file);
        ogg_sync_wrote(&syncState, bytes);

        if (bytes == 0) {
            break; // End of file
        }

        // Process available pages
        while (ogg_sync_pageout(&syncState, &page) == 1) {
            // Initialize stream state for new logical stream
            if (ogg_page_bos(&page)) {
                ogg_stream_init(&streamState, ogg_page_serialno(&page));
            }

            ogg_stream_pagein(&streamState, &page);

            // Process packets in the page
            while (ogg_stream_packetout(&streamState, &packet) == 1) {
                // Parse Opus header packets
                if (!headerParsed && packet.bytes >= 8 && 
                    memcmp(packet.packet, "OpusHead", 8) == 0) {

                    // Parse Opus header
                    if (packet.bytes >= 19) {
                        unsigned char* data = packet.packet;
                        channels = data[9];
                        sampleRate = (data[12] | (data[13] << 8) | 
                                     (data[14] << 16) | (data[15] << 24));

                        // Initialize Opus decoder
                        int error;
                        opusDecoder = opus_decoder_create(sampleRate, channels, &error);
                        if (error != OPUS_OK || !opusDecoder) {
                            success = false;
                            break;
                        }

                        headerParsed = true;
                        continue;
                    }
                }

                // Skip comment header
                if (!headerParsed && packet.bytes >= 8 && 
                    memcmp(packet.packet, "OpusTags", 8) == 0) {
                    continue;
                }

                // Decode audio packets
                if (headerParsed && opusDecoder) {
                    // Maximum frame size for 120ms at highest sample rate
                    const int maxFrameSize = 960 * 6;
                    opus_int16 pcm[maxFrameSize * channels];

                    int frameSize = opus_decode(opusDecoder, 
                                              packet.packet, 
                                              packet.bytes, 
                                              pcm, 
                                              maxFrameSize, 
                                              0);

                    if (frameSize > 0) {
                        // Send decoded PCM data to audio output
                        if (!SendAudioToOutput(pcm, frameSize, channels, sampleRate)) {
                            success = false;
                            break;
                        }
                    } else if (frameSize < 0) {
                        // Decoding error
                        success = false;
                        break;
                    }
                }
            }

            // Check if this was the last page
            if (ogg_page_eos(&page)) {
                break;
            }
        }
    }

    // Cleanup
    if (opusDecoder) {
        opus_decoder_destroy(opusDecoder);
    }

    ogg_stream_clear(&streamState);
    ogg_sync_clear(&syncState);
    fclose(file);

    return success;
}

void AudioService::SetModelsList(srmodel_list_t* model_list) {
    if (model_list == nullptr) {
        return;
    }

    // Store the model list
    this->model_list_ = model_list;

    // Reset current wake word engine
    if (wake_word_engine_) {
        wake_word_engine_->Deinitialize();
        wake_word_engine_.reset();
    }

    // Determine the best wake word engine based on models and hardware
    WakeWordEngineType selected_engine_type = WAKE_WORD_ENGINE_NONE;

    // Check each model to determine available engines
    for (int i = 0; i < model_list->num; i++) {
        const char* model_name = model_list->models[i].name;

        // Check for custom wake word models (prefix-based detection)
        if (strncmp(model_name, "custom_wake_", 12) == 0) {
            selected_engine_type = WAKE_WORD_ENGINE_CUSTOM;
            break;
        }
        // Check for AFE-based wake word models
        else if (strncmp(model_name, "afe_wake_", 9) == 0) {
            // Verify AFE hardware is available
            if (IsAFEHardwareAvailable()) {
                selected_engine_type = WAKE_WORD_ENGINE_AFE;
                break;
            }
        }
        // Check for ESP-based wake word models
        else if (strncmp(model_name, "esp_wake_", 9) == 0) {
            // Verify ESP platform compatibility
            if (IsESPPlatformSupported()) {
                selected_engine_type = WAKE_WORD_ENGINE_ESP;
                break;
            }
        }
    }

    // Initialize the selected wake word engine
    bool engine_initialized = false;

    switch (selected_engine_type) {
        case WAKE_WORD_ENGINE_CUSTOM:
            wake_word_engine_ = std::make_unique<CustomWakeWordEngine>();
            engine_initialized = wake_word_engine_->Initialize(model_list);
            break;

        case WAKE_WORD_ENGINE_AFE:
            wake_word_engine_ = std::make_unique<AFEWakeWordEngine>();
            engine_initialized = wake_word_engine_->Initialize(model_list);
            break;

        case WAKE_WORD_ENGINE_ESP:
            wake_word_engine_ = std::make_unique<ESPWakeWordEngine>();
            engine_initialized = wake_word_engine_->Initialize(model_list);
            break;

        default:
            // No suitable wake word engine found
            wake_word_engine_ = nullptr;
            break;
    }

    // Register callback if engine was successfully initialized
    if (engine_initialized && wake_word_engine_) {
        wake_word_engine_->RegisterDetectionCallback(
            std::bind(&AudioService::OnWakeWordDetected, this, std::placeholders::_1)
        );
    }

    // Update service state
    wake_word_enabled_ = (engine_initialized && wake_word_engine_);
}

Es8388AudioCodec::Es8388AudioCodec(
    void *i2s_config,
    i2c_port_t i2c_port,
    int sample_rate_1,
    int sample_rate_2,
    gpio_num_t pa_power_pin,
    gpio_num_t mclk_pin,
    gpio_num_t sclk_pin,
    gpio_num_t ws_pin,
    gpio_num_t data_in_pin,
    gpio_num_t data_out_pin,
    uint8_t i2c_addr,
    bool aec_enabled
) : i2c_port_(i2c_port), 
    i2c_addr_(i2c_addr),
    sample_rate_1_(sample_rate_1),
    sample_rate_2_(sample_rate_2),
    pa_power_pin_(pa_power_pin),
    aec_enabled_(aec_enabled) {

    // Initialize GPIO for power amplifier control
    gpio_config_t pa_gpio_config;
    pa_gpio_config.pin_bit_mask = (1ULL << pa_power_pin_);
    pa_gpio_config.mode = GPIO_MODE_OUTPUT;
    pa_gpio_config.pull_up_en = GPIO_PULLUP_DISABLE;
    pa_gpio_config.pull_down_en = GPIO_PULLDOWN_DISABLE;
    pa_gpio_config.intr_type = GPIO_INTR_DISABLE;
    gpio_config(&pa_gpio_config);

    // Set initial state of power amplifier to off
    gpio_set_level(pa_power_pin_, 0);

    // Initialize I2C interface for codec control
    i2c_config_t conf;
    conf.mode = I2C_MODE_MASTER;
    conf.sda_io_num = I2C_SDA_PIN;  // Assuming standard pin definitions
    conf.sda_pullup_en = GPIO_PULLUP_ENABLE;
    conf.scl_io_num = I2C_SCL_PIN;  // Assuming standard pin definitions
    conf.scl_pullup_en = GPIO_PULLUP_ENABLE;
    conf.master.clk_speed = 100000;  // 100kHz standard speed

    i2c_param_config(i2c_port_, &conf);
    i2c_driver_install(i2c_port_, conf.mode, 0, 0, 0);

    // Initialize I2S interfaces for audio data
    i2s_config_t i2s_cfg = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX | I2S_MODE_RX),
        .sample_rate = (uint32_t)sample_rate_1_,
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
        .communication_format = I2S_COMM_FORMAT_I2S,
        .intr_alloc_flags = 0,
        .dma_buf_count = 8,
        .dma_buf_len = 64,
        .use_apll = false,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0
    };

    i2s_pin_config_t pin_cfg = {
        .mck_io_num = mclk_pin,
        .bck_io_num = sclk_pin,
        .ws_io_num = ws_pin,
        .data_out_num = data_out_pin,
        .data_in_num = data_in_pin
    };

    // Install and configure I2S driver
    i2s_driver_install(I2S_NUM_0, &i2s_cfg, 0, NULL);
    i2s_set_pin(I2S_NUM_0, &pin_cfg);

    // Reset the codec
    es8388_write_reg(ES8388_CONTROL1, 0x80); // Reset register
    vTaskDelay(10 / portTICK_RATE_MS);
    es8388_write_reg(ES8388_CONTROL1, 0x00); // Clear reset

    // Configure power management
    es8388_write_reg(ES8388_CHIPPOWER, 0xFF); // Power down all modules initially
    es8388_write_reg(ES8388_ADCPOWER, 0xFF);  // Power down ADC
    es8388_write_reg(ES8388_DACPOWER, 0xFF);  // Power down DAC

    // Configure clock management
    es8388_write_reg(ES8388_MASTERMODE, 0x00); // Slave mode
    es8388_write_reg(ES8388_CLOCKMANAGEMENT, 0x00);

    // Set sample rate
    uint8_t sample_rate_reg = 0x00;
    switch(sample_rate_1_) {
        case 8000:  sample_rate_reg = 0x08; break;
        case 11025: sample_rate_reg = 0x10; break;
        case 16000: sample_rate_reg = 0x18; break;
        case 22050: sample_rate_reg = 0x20; break;
        case 32000: sample_rate_reg = 0x28; break;
        case 44100: sample_rate_reg = 0x30; break;
        case 48000: sample_rate_reg = 0x38; break;
        default:    sample_rate_reg = 0x30; break; // Default to 44.1kHz
    }
    es8388_write_reg(ES8388_ADCRATE, sample_rate_reg);
    es8388_write_reg(ES8388_DACRATE, sample_rate_reg);

    // Configure ADC (input)
    es8388_write_reg(ES8388_ADCCONTROL1, 0xBB); // Mono, L/R inverted
    es8388_write_reg(ES8388_ADCCONTROL2, 0x02); // LPF enable
    es8388_write_reg(ES8388_ADCCONTROL3, 0x02); // Input volume control
    es8388_write_reg(ES8388_ADCCONTROL4, 0x02); // Input gain control

    // Configure DAC (output)
    es8388_write_reg(ES8388_DACCONTROL1, 0x18); // DAC output mix enable
    es8388_write_reg(ES8388_DACCONTROL2, 0x02); // DAC volume control
    es8388_write_reg(ES8388_DACCONTROL3, 0x00); // DAC attenuation

    // Configure input channels
    es8388_write_reg(ES8388_LADCINPUT, 0x00);   // Left ADC input
    es8388_write_reg(ES8388_RADCINPUT, 0x00);   // Right ADC input

    // Configure output channels
    es8388_write_reg(ES8388_LOUT1VOL, 0x1E);    // Left output volume
    es8388_write_reg(ES8388_ROUT1VOL, 0x1E);    // Right output volume

    // Enable necessary modules
    es8388_write_reg(ES8388_CHIPPOWER, 0x00);   // Power up all modules
    es8388_write_reg(ES8388_ADCPOWER, 0x09);    // Power up ADC, MICBIAS
    es8388_write_reg(ES8388_DACPOWER, 0x30);    // Power up DAC

    // If AEC is enabled, configure reference input
    if (aec_enabled_) {
        // Configure additional input path for reference signal
        es8388_write_reg(ES8388_ADCCONTROL5, 0x01); // Enable reference input
    }

    // Start I2S peripheral
    i2s_zero_dma_buffer(I2S_NUM_0);
}

// Helper function to write to ES8388 registers
esp_err_t Es8388AudioCodec::es8388_write_reg(uint8_t reg_addr, uint8_t data) {
    i2c_cmd_handle_t cmd = i2c_cmd_link_create();
    i2c_master_start(cmd);
    i2c_master_write_byte(cmd, (i2c_addr_ << 1) | I2C_MASTER_WRITE, true);
    i2c_master_write_byte(cmd, reg_addr, true);
    i2c_master_write_byte(cmd, data, true);
    i2c_master_stop(cmd);
    esp_err_t ret = i2c_master_cmd_begin(i2c_port_, cmd, 1000 / portTICK_RATE_MS);
    i2c_cmd_link_delete(cmd);
    return ret;
}

esp_err_t CreateDuplexChannels(gpio_num_t bck_pin, gpio_num_t ws_pin, gpio_num_t data_out_pin, gpio_num_t data_in_pin, gpio_num_t mclk_pin)
{
    // Configure I2S driver for full-duplex operation
    i2s_driver_config_t i2s_config = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX | I2S_MODE_RX),
        .sample_rate = 44100,
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
        .communication_format = I2S_COMM_FORMAT_I2S,
        .intr_alloc_flags = 0,
        .dma_buf_count = 8,
        .dma_buf_len = 64,
        .use_apll = true,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0,
        .mclk_multiple = I2S_MCLK_MULTIPLE_256,
        .bits_per_chan = I2S_BITS_PER_CHAN_16BIT,
    };

    // Install and start I2S driver
    esp_err_t ret = i2s_driver_install(I2S_NUM_0, &i2s_config, 0, NULL);
    if (ret != ESP_OK) {
        return ret;
    }

    // Configure I2S pin mapping
    i2s_pin_config_t pin_config = {
        .mck_io_num = mclk_pin,
        .bck_io_num = bck_pin,
        .ws_io_num = ws_pin,
        .data_out_num = data_out_pin,
        .data_in_num = data_in_pin
    };

    ret = i2s_set_pin(I2S_NUM_0, &pin_config);
    if (ret != ESP_OK) {
        i2s_driver_uninstall(I2S_NUM_0);
        return ret;
    }

    // Set clock configuration
    ret = i2s_set_clk(I2S_NUM_0, 44100, I2S_BITS_PER_SAMPLE_16BIT, I2S_CHANNEL_STEREO);
    if (ret != ESP_OK) {
        i2s_driver_uninstall(I2S_NUM_0);
        return ret;
    }

    // Zero-initialize the DMA buffers to prevent noise
    i2s_zero_dma_buffer(I2S_NUM_0);

    return ESP_OK;
}

void EnableInput(bool enable) {
    if (enable) {
        // Configure ES8388 input registers
        // Set ADC power control
        WriteRegister(ES8388_ADCPOWER, 0x00); // Power up ADC

        // Configure ADC control registers
        WriteRegister(ES8388_ADCCONTROL1, 0x00); // ADC digital microphone off, normal mode
        WriteRegister(ES8388_ADCCONTROL2, 0x00); // ADC soft reset off, MCLK/LRCK ratio

        // Set sample rate and format
        WriteRegister(ES8388_ADCCONTROL3, 0x02); // ADC sample rate
        WriteRegister(ES8388_ADCCONTROL4, 0x00); // ADC format: I2S, 16-bit

        // Configure input gain
        WriteRegister(ES8388_ADCCONTROL5, 0x20); // ADC volume control - left channel
        WriteRegister(ES8388_ADCCONTROL6, 0x20); // ADC volume control - right channel

        // Configure microphone input
        WriteRegister(ES8388_ADCCONTROL7, 0x00); // ADC L/R channel PGA gain
        WriteRegister(ES8388_ADCCONTROL8, 0x00); // ADC mute, PGA gain control

        // Select input source (mic/line-in)
        WriteRegister(ES8388_ADCCONTROL9, 0x01); // Select microphone input

        // Unmute ADC
        WriteRegister(ES8388_ADCCONTROL10, 0x00); // Unmute ADC output

        // Open input device for audio capture
        OpenInputDevice();

        // Apply additional gain settings if needed
        ApplyInputGain();
    } else {
        // Mute ADC before shutting down
        WriteRegister(ES8388_ADCCONTROL10, 0xC0); // Mute ADC output

        // Power down ADC
        WriteRegister(ES8388_ADCPOWER, 0xFF); // Power down ADC

        // Close input device to stop audio capture
        CloseInputDevice();
    }
}

void EnableOutput(bool enable) {
    if (enable) {
        // Enable the codec output
        // Configure sample rate settings
        ES8388_WriteReg(ES8388_DACCONTROL1, 0x00); // DAC oversampling frequency ratio
        ES8388_WriteReg(ES8388_DACCONTROL2, 0x02); // DAC MCLK/LRCK ratio
        ES8388_WriteReg(ES8388_DACCONTROL3, 0x00); // DAC path selection

        // Configure volume settings
        ES8388_WriteReg(ES8388_DACCONTROL4, 0x1E); // Left DAC volume
        ES8388_WriteReg(ES8388_DACCONTROL5, 0x1E); // Right DAC volume

        // Set analog output levels
        ES8388_WriteReg(ES8388_ANAVOLMANAG, 0x00); // Analog volume management
        ES8388_WriteReg(ES8388_MASTERMODE, 0x00);  // Master volume control

        // Enable DAC and analog output
        ES8388_WriteReg(ES8388_CHIPPOWER, 0x00);   // Power up DAC and analog blocks
        ES8388_WriteReg(ES8388_DACPOWER, 0xC0);    // Power up DAC L/R channels

        // Configure output mixer
        ES8388_WriteReg(ES8388_DACCONTROL16, 0x00); // Left channel mixer
        ES8388_WriteReg(ES8388_DACCONTROL17, 0x00); // Right channel mixer

        // Activate power amplifier pin if present
        #ifdef POWER_AMP_PIN
        digitalWrite(POWER_AMP_PIN, HIGH);
        pinMode(POWER_AMP_PIN, OUTPUT);
        #endif

        // Enable I2S output
        ES8388_WriteReg(ES8388_MASTERMODE, 0x00);  // Set master mode
    } else {
        // Disable the codec output
        // Close codec output device
        ES8388_WriteReg(ES8388_DACPOWER, 0xFF);    // Power down DAC L/R channels
        ES8388_WriteReg(ES8388_CHIPPOWER, 0xFF);   // Power down all blocks

        // Deactivate power amplifier pin if present
        #ifdef POWER_AMP_PIN
        digitalWrite(POWER_AMP_PIN, LOW);
        #endif
    }
}

AudioDebugger::AudioDebugger() {
    // Initialize member variables
    m_udpSocket = -1;
    m_isInitialized = false;
    m_serverPort = 0;

    // Get configuration settings for server IP and port
    std::string serverIP = getConfigServerIP();
    m_serverPort = getConfigServerPort();

    // Validate configuration parameters
    if (serverIP.empty() || m_serverPort == 0) {
        logError("Invalid server configuration: IP or port not set");
        return;
    }

    // Create UDP socket
    m_udpSocket = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (m_udpSocket < 0) {
        logError("Failed to create UDP socket: " + std::string(strerror(errno)));
        return;
    }

    // Configure server address structure
    memset(&m_serverAddr, 0, sizeof(m_serverAddr));
    m_serverAddr.sin_family = AF_INET;
    m_serverAddr.sin_port = htons(m_serverPort);

    // Parse and set server IP address
    if (inet_pton(AF_INET, serverIP.c_str(), &m_serverAddr.sin_addr) <= 0) {
        logError("Failed to parse server IP address: " + serverIP);
        close(m_udpSocket);
        m_udpSocket = -1;
        return;
    }

    // Test connection by sending a simple debug message
    const char* testMessage = "AudioDebugger initialized";
    ssize_t sentBytes = sendto(m_udpSocket, testMessage, strlen(testMessage), 
                              0, (struct sockaddr*)&m_serverAddr, sizeof(m_serverAddr));

    if (sentBytes < 0) {
        logError("Failed to send test message to server: " + std::string(strerror(errno)));
        close(m_udpSocket);
        m_udpSocket = -1;
        return;
    }

    // Mark as successfully initialized
    m_isInitialized = true;
    logInfo("AudioDebugger successfully initialized. Connected to " + serverIP + ":" + std::to_string(m_serverPort));
}

bool AfeWakeWord::Initialize(AudioCodec* audioCodec, srmodel_list_t* modelList) {
    // Validate input parameters
    if (audioCodec == nullptr || modelList == nullptr) {
        return false;
    }

    // Store references
    m_audioCodec = audioCodec;
    m_modelList = modelList;

    // Configure audio codec for wake word detection
    if (!m_audioCodec->Configure(kSampleRate, kChannelCount, kBitDepth)) {
        return false;
    }

    // Initialize AFE processing pipeline
    m_afeConfig.sample_rate = kSampleRate;
    m_afeConfig.channels = kChannelCount;
    m_afeConfig.echo_cancellation_enabled = true;
    m_afeConfig.beamforming_enabled = false;
    m_afeConfig.memory_pool_size = kMemoryPoolSize;

    if (!AfePipelineInit(&m_afeConfig, &m_afeHandle)) {
        return false;
    }

    // Load wake word models
    for (int i = 0; i < modelList->count; i++) {
        if (!LoadWakeWordModel(modelList->models[i])) {
            // Cleanup previously loaded models
            UnloadWakeWordModels();
            AfePipelineDeinit(m_afeHandle);
            return false;
        }
    }

    // Allocate memory for audio buffers
    m_audioBuffer = static_cast<int16_t*>(malloc(kBufferSize * sizeof(int16_t)));
    if (m_audioBuffer == nullptr) {
        UnloadWakeWordModels();
        AfePipelineDeinit(m_afeHandle);
        return false;
    }

    // Create audio detection task
    m_detectionTaskHandle = xTaskCreateStatic(
        AudioDetectionTask,
        "AfeWakeWord",
        kTaskStackSize,
        this,
        kTaskPriority,
        m_taskStackBuffer,
        &m_taskControlBlock
    );

    if (m_detectionTaskHandle == NULL) {
        free(m_audioBuffer);
        UnloadWakeWordModels();
        AfePipelineDeinit(m_afeHandle);
        return false;
    }

    // Start audio capture
    if (!m_audioCodec->StartCapture()) {
        vTaskDelete(m_detectionTaskHandle);
        free(m_audioBuffer);
        UnloadWakeWordModels();
        AfePipelineDeinit(m_afeHandle);
        return false;
    }

    m_initialized = true;
    return true;
}

void AfeWakeWord::AudioDetectionTask() {
    // Initialize detection state
    bool detectionRunning = true;
    WakeWordDetectedCallback callback = this->wakeWordCallback;

    // Ensure AFE is properly initialized
    if (!afeInterface || !callback) {
        return;
    }

    // Main detection loop
    while (detectionRunning && !shutdownRequested) {
        // Read audio data from input stream
        AudioBuffer audioData;
        AudioResult result = audioInputStream->Read(audioData);

        if (result != AUDIO_SUCCESS) {
            // Handle audio read errors
            if (result == AUDIO_DISCONNECTED) {
                break; // Exit if audio source is disconnected
            }
            continue; // Skip this iteration on other errors
        }

        // Feed audio data to acoustic front-end for processing
        AfeResult afeResult = afeInterface->ProcessAudio(audioData);

        if (afeResult != AFE_SUCCESS) {
            continue; // Skip if AFE processing failed
        }

        // Check if wake word was detected
        WakeWordDetectionInfo detectionInfo;
        if (afeInterface->IsWakeWordDetected(detectionInfo)) {
            // Stop the detection process
            detectionRunning = false;

            // Store relevant audio data (pre-roll/buffered audio)
            AudioBuffer wakeWordAudio;
            if (afeInterface->GetWakeWordAudio(wakeWordAudio)) {
                // Store the audio data for further processing
                storedAudioData = wakeWordAudio;
            }

            // Extract wake word information
            std::string detectedWakeWord = detectionInfo.wakeWord;
            uint32_t timestamp = detectionInfo.timestamp;
            float confidence = detectionInfo.confidence;

            // Validate wake word before triggering callback
            if (!detectedWakeWord.empty() && confidence >= MIN_CONFIDENCE_THRESHOLD) {
                // Trigger callback with detected wake word information
                WakeWordEvent event;
                event.wakeWord = detectedWakeWord;
                event.timestamp = timestamp;
                event.confidence = confidence;
                event.audioData = wakeWordAudio;

                // Call the registered callback
                callback(event);
            }
        }

        // Optional: Add small delay to prevent busy waiting
        // This allows other threads/system tasks to execute
        if (detectionRunning) {
            Thread::Sleep(DETECTION_LOOP_DELAY_MS);
        }
    }

    // Cleanup resources if shutdown was requested
    if (shutdownRequested) {
        afeInterface->Stop();
        audioInputStream->Close();
    }
}

bool AfeWakeWord::EncodeWakeWordData(const int16_t* pcmData, size_t pcmSize, uint32_t sampleRate, uint8_t channels)
{
    if (!pcmData || pcmSize == 0) {
        return false;
    }

    // Allocate memory for task stack (prefer SPIRAM if available)
    void* taskStack = nullptr;
    const size_t stackSize = 8192; // 8KB stack for encoding task

    #ifdef CONFIG_SPIRAM_SUPPORT
        taskStack = heap_caps_malloc(stackSize, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
    #endif

    if (!taskStack) {
        taskStack = malloc(stackSize);
        if (!taskStack) {
            return false;
        }
    }

    // Initialize Opus encoder with low complexity settings
    int opusError = 0;
    OpusEncoder* encoder = opus_encoder_create(sampleRate, channels, OPUS_APPLICATION_VOIP, &opusError);
    if (opusError != OPUS_OK || !encoder) {
        free(taskStack);
        return false;
    }

    // Set low complexity for fast encoding
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(OPUS_AUTO));
    opus_encoder_ctl(encoder, OPUS_SET_VBR(1));

    // Prepare encoding parameters
    const int frameSize = sampleRate * 0.02f; // 20ms frames
    const int maxPacketSize = 4000;
    std::vector<uint8_t> encodedBuffer(maxPacketSize);

    // Thread-safe buffer for encoded data
    static std::mutex encodeMutex;
    static std::condition_variable encodeComplete;
    static std::queue<std::vector<uint8_t>> encodedPackets;
    static bool encodingFinished = false;

    // Encoding task function
    auto encodingTask = [this, encoder, pcmData, pcmSize, frameSize, maxPacketSize, 
                        &encodedBuffer, &encodeMutex, &encodeComplete, &encodedPackets, &encodingFinished]() {

        size_t samplesProcessed = 0;
        const size_t totalSamples = pcmSize / sizeof(int16_t);
        const int16_t* pcmPtr = pcmData;

        while (samplesProcessed < totalSamples) {
            int samplesToProcess = std::min(frameSize, static_cast<int>(totalSamples - samplesProcessed));

            // Encode PCM frame to Opus
            int encodedBytes = opus_encode(encoder, pcmPtr + samplesProcessed, samplesToProcess,
                                         encodedBuffer.data(), maxPacketSize);

            if (encodedBytes > 0) {
                // Store encoded packet in thread-safe buffer
                std::lock_guard<std::mutex> lock(encodeMutex);
                std::vector<uint8_t> packet(encodedBuffer.begin(), encodedBuffer.begin() + encodedBytes);
                encodedPackets.push(packet);
            }

            samplesProcessed += samplesToProcess;
        }

        // Signal completion
        {
            std::lock_guard<std::mutex> lock(encodeMutex);
            encodingFinished = true;
        }
        encodeComplete.notify_all();
    };

    // Create real-time encoding task
    TaskHandle_t encodingTaskHandle = nullptr;
    BaseType_t result = xTaskCreate(encodingTask, "OpusEncodingTask", 
                                   stackSize / sizeof(StackType_t), 
                                   nullptr, 
                                   configMAX_PRIORITIES - 1, // High priority for real-time processing
                                   &encodingTaskHandle);

    if (result != pdPASS) {
        opus_encoder_destroy(encoder);
        free(taskStack);
        return false;
    }

    // Wait for encoding completion with timeout
    std::unique_lock<std::mutex> lock(encodeMutex);
    if (encodeComplete.wait_for(lock, std::chrono::milliseconds(5000), [&](){ return encodingFinished; })) {
        // Encoding completed successfully
        // Here you would typically process the encodedPackets queue
        // For example: transfer to main buffer or send to network

        // Cleanup
        if (encodingTaskHandle) {
            vTaskDelete(encodingTaskHandle);
        }
        opus_encoder_destroy(encoder);

        // Free task stack memory
        #ifdef CONFIG_SPIRAM_SUPPORT
            heap_caps_free(taskStack);
        #else
            free(taskStack);
        #endif

        return true;
    } else {
        // Timeout occurred
        if (encodingTaskHandle) {
            vTaskDelete(encodingTaskHandle);
        }
        opus_encoder_destroy(encoder);

        #ifdef CONFIG_SPIRAM_SUPPORT
            heap_caps_free(taskStack);
        #else
            free(taskStack);
        #endif

        return false;
    }
}

bool CustomWakeWord::ParseWakenetModelConfig(const std::string& configPath) {
    try {
        // Read the JSON configuration file
        std::ifstream configFile(configPath);
        if (!configFile.is_open()) {
            ESP_LOGE(TAG, "Failed to open configuration file: %s", configPath.c_str());
            return false;
        }

        // Parse JSON content
        json configJson;
        configFile >> configJson;
        configFile.close();

        // Extract language setting
        if (configJson.contains("language")) {
            m_language = configJson["language"].get<std::string>();
            ESP_LOGI(TAG, "Language configured: %s", m_language.c_str());
        } else {
            ESP_LOGW(TAG, "Language not specified in configuration, using default");
            m_language = "en"; // Default to English
        }

        // Extract duration setting
        if (configJson.contains("duration")) {
            m_duration = configJson["duration"].get<int>();
            ESP_LOGI(TAG, "Duration configured: %d seconds", m_duration);
        } else {
            ESP_LOGW(TAG, "Duration not specified in configuration, using default");
            m_duration = 3; // Default to 3 seconds
        }

        // Extract threshold setting
        if (configJson.contains("threshold")) {
            m_threshold = configJson["threshold"].get<float>();
            ESP_LOGI(TAG, "Threshold configured: %.2f", m_threshold);
        } else {
            ESP_LOGW(TAG, "Threshold not specified in configuration, using default");
            m_threshold = 0.5f; // Default threshold
        }

        // Extract and parse command definitions
        if (configJson.contains("commands") && configJson["commands"].is_array()) {
            m_commands.clear();
            auto commandsArray = configJson["commands"];

            for (const auto& command : commandsArray) {
                if (command.contains("name") && command.contains("id")) {
                    WakeWordCommand cmd;
                    cmd.name = command["name"].get<std::string>();
                    cmd.id = command["id"].get<int>();

                    // Optional confidence threshold per command
                    if (command.contains("threshold")) {
                        cmd.threshold = command["threshold"].get<float>();
                    } else {
                        cmd.threshold = m_threshold; // Use global threshold
                    }

                    m_commands.push_back(cmd);

                    // Log the parsed command for debugging
                    ESP_LOGI(TAG, "Parsed command: %s (ID: %d, Threshold: %.2f)", 
                             cmd.name.c_str(), cmd.id, cmd.threshold);
                } else {
                    ESP_LOGW(TAG, "Skipping invalid command definition in configuration");
                }
            }

            ESP_LOGI(TAG, "Total commands loaded: %d", m_commands.size());
        } else {
            ESP_LOGW(TAG, "No valid commands found in configuration");
            m_commands.clear();
        }

        // Additional model-specific configurations
        if (configJson.contains("model_version")) {
            m_modelVersion = configJson["model_version"].get<std::string>();
            ESP_LOGI(TAG, "Model version: %s", m_modelVersion.c_str());
        }

        if (configJson.contains("sample_rate")) {
            m_sampleRate = configJson["sample_rate"].get<int>();
            ESP_LOGI(TAG, "Sample rate configured: %d Hz", m_sampleRate);
        }

        // Mark configuration as loaded successfully
        m_isConfigLoaded = true;
        ESP_LOGI(TAG, "Wakenet model configuration loaded successfully from %s", configPath.c_str());

        return true;

    } catch (const json::exception& e) {
        ESP_LOGE(TAG, "JSON parsing error: %s", e.what());
        return false;
    } catch (const std::exception& e) {
        ESP_LOGE(TAG, "Error parsing wakenet configuration: %s", e.what());
        return false;
    } catch (...) {
        ESP_LOGE(TAG, "Unknown error occurred while parsing configuration");
        return false;
    }
}

bool CustomWakeWord::Initialize(AudioCodec* audioCodec, srmodel_list_t* modelList) {
    // Validate input parameters
    if (audioCodec == nullptr || modelList == nullptr) {
        return false;
    }

    // Configure the audio codec for wake word detection
    if (!audioCodec->initialize()) {
        return false;
    }

    // Set audio parameters for wake word detection
    if (!audioCodec->setSampleRate(WAKE_WORD_SAMPLE_RATE)) {
        return false;
    }

    if (!audioCodec->setChannelCount(WAKE_WORD_CHANNEL_COUNT)) {
        return false;
    }

    if (!audioCodec->setBitDepth(WAKE_WORD_BIT_DEPTH)) {
        return false;
    }

    // Load voice recognition models from the model list
    if (!loadRecognitionModels(modelList)) {
        return false;
    }

    // Initialize the multinet model for speech command recognition
    if (!initializeMultinetModel()) {
        return false;
    }

    // Register custom voice commands
    if (!registerCustomCommands()) {
        return false;
    }

    // Apply language settings
    if (!configureLanguageSettings()) {
        return false;
    }

    // Apply threshold settings for wake word detection
    if (!configureThresholdSettings()) {
        return false;
    }

    // Start audio capture for wake word detection
    if (!audioCodec->startCapture()) {
        return false;
    }

    // Mark initialization as complete
    m_initialized = true;

    return true;
}

void CustomWakeWord::Feed(const std::vector<int16_t>& audioData) {
    // Check if detection is currently active
    if (!m_isActive) {
        return;
    }

    // Handle empty input
    if (audioData.empty()) {
        return;
    }

    // Process audio data based on channel configuration
    std::vector<int16_t> processedAudio;
    if (m_isStereo) {
        // Extract left channel from stereo input (every other sample)
        processedAudio.reserve(audioData.size() / 2);
        for (size_t i = 0; i < audioData.size(); i += 2) {
            processedAudio.push_back(audioData[i]);
        }
    } else {
        // Mono input - use as is
        processedAudio = audioData;
    }

    // Append to internal buffer
    m_audioBuffer.insert(m_audioBuffer.end(), processedAudio.begin(), processedAudio.end());

    // Process buffered audio through multinet model
    while (m_audioBuffer.size() >= m_frameSize) {
        // Extract a frame for processing
        std::vector<int16_t> frame(m_audioBuffer.begin(), m_audioBuffer.begin() + m_frameSize);

        // Run wake word detection on the frame
        int detectedWordId = m_multinetModel->detect(frame);

        // Check if a wake word was detected
        if (detectedWordId >= 0 && detectedWordId < static_cast<int>(m_wakeWords.size())) {
            // Wake word detected - trigger callback
            if (m_detectionCallback) {
                m_detectionCallback(m_wakeWords[detectedWordId]);
            }

            // Deactivate detection until reactivated
            m_isActive = false;

            // Clear buffer to start fresh after reactivation
            m_audioBuffer.clear();

            return;
        }

        // Remove processed portion from buffer (with overlap for continuity)
        size_t removeSize = m_frameSize - m_frameOverlap;
        if (m_audioBuffer.size() > removeSize) {
            m_audioBuffer.erase(m_audioBuffer.begin(), m_audioBuffer.begin() + removeSize);
        } else {
            m_audioBuffer.clear();
        }
    }
}

bool EncodeWakeWordData()
{
    // Configuration parameters
    const int OPUS_SAMPLE_RATE = 16000;
    const int OPUS_CHANNELS = 1;
    const int OPUS_FRAME_SIZE = 960; // 60ms at 16kHz
    const int OPUS_BITRATE = 24000;
    const int STACK_SIZE = 8192;
    const int BUFFER_SIZE = 4096;

    // Memory allocation for task stack and buffer
    uint8_t* taskStack = (uint8_t*)malloc(STACK_SIZE);
    if (!taskStack) {
        return false;
    }

    uint8_t* encodeBuffer = (uint8_t*)malloc(BUFFER_SIZE);
    if (!encodeBuffer) {
        free(taskStack);
        return false;
    }

    // Initialize Opus encoder with low complexity settings
    int opusError = 0;
    OpusEncoder* encoder = opus_encoder_create(OPUS_SAMPLE_RATE, OPUS_CHANNELS, OPUS_APPLICATION_VOIP, &opusError);
    if (opusError != OPUS_OK || !encoder) {
        free(taskStack);
        free(encodeBuffer);
        return false;
    }

    // Set low complexity encoding
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(OPUS_BITRATE));
    opus_encoder_ctl(encoder, OPUS_SET_VBR(1));

    // Create background task to handle encoding
    // Using a lambda to capture necessary variables
    auto encodingTask = [encoder, encodeBuffer, taskStack]() {
        // Get access to stored PCM data (assuming it's globally accessible or passed)
        extern std::vector<int16_t> storedPcmData;
        extern std::vector<uint8_t> encodedOpusData;
        extern std::mutex encodedDataMutex;
        extern std::condition_variable encodingComplete;
        extern bool encodingFinished;

        size_t pcmIndex = 0;
        std::lock_guard<std::mutex> lock(encodedDataMutex);

        // Process PCM data in frames
        while (pcmIndex + OPUS_FRAME_SIZE <= storedPcmData.size()) {
            // Encode one frame of PCM data
            int encodedBytes = opus_encode(encoder, 
                                         &storedPcmData[pcmIndex], 
                                         OPUS_FRAME_SIZE, 
                                         encodeBuffer, 
                                         BUFFER_SIZE);

            if (encodedBytes > 0) {
                // Append encoded data to output buffer
                encodedOpusData.insert(encodedOpusData.end(), encodeBuffer, encodeBuffer + encodedBytes);
            }

            pcmIndex += OPUS_FRAME_SIZE;
        }

        // Append termination marker (using Opus TOC for self-delimiting)
        // Simple approach: add zero-length frame as termination
        uint8_t terminationMarker[1] = {0};
        encodedOpusData.push_back(terminationMarker[0]);

        // Cleanup encoder
        opus_encoder_destroy(encoder);

        // Signal completion
        encodingFinished = true;
        encodingComplete.notify_all();

        // Free allocated memory
        free(encodeBuffer);
        free(taskStack);
    };

    // Spawn background thread for encoding
    try {
        std::thread encodingThread(encodingTask);
        encodingThread.detach(); // Run in background
    } catch (...) {
        // Cleanup on failure
        opus_encoder_destroy(encoder);
        free(encodeBuffer);
        free(taskStack);
        return false;
    }

    return true;
}

void InitializeSt7789Display() {
    // Initialize SPI interface
    spi_init(ST7789_SPI_PORT, ST7789_SPI_BAUD_RATE);
    gpio_set_function(ST7789_SCK_PIN, GPIO_FUNC_SPI);
    gpio_set_function(ST7789_MOSI_PIN, GPIO_FUNC_SPI);
    gpio_set_function(ST7789_MISO_PIN, GPIO_FUNC_SPI);

    // Configure control pins
    gpio_init(ST7789_CS_PIN);
    gpio_set_dir(ST7789_CS_PIN, GPIO_OUT);
    gpio_put(ST7789_CS_PIN, 1);

    gpio_init(ST7789_DC_PIN);
    gpio_set_dir(ST7789_DC_PIN, GPIO_OUT);
    gpio_put(ST7789_DC_PIN, 0);

    gpio_init(ST7789_RST_PIN);
    gpio_set_dir(ST7789_RST_PIN, GPIO_OUT);
    gpio_put(ST7789_RST_PIN, 1);

    // Reset the display
    gpio_put(ST7789_RST_PIN, 0);
    sleep_ms(100);
    gpio_put(ST7789_RST_PIN, 1);
    sleep_ms(100);

    // Wake up from sleep
    st7789_write_command(0x11); // Sleep Out
    sleep_ms(120);

    // Configure memory access control (orientation, mirroring)
    st7789_write_command(0x36); // Memory Access Control
    uint8_t madctl = 0x00;

    // Apply axis swapping and mirroring based on configuration
    #ifdef DISPLAY_SWAP_XY
        madctl |= 0x20; // MV bit for swapping X and Y
    #endif

    #ifdef DISPLAY_MIRROR_X
        madctl |= 0x40; // MX bit for X mirroring
    #endif

    #ifdef DISPLAY_MIRROR_Y
        madctl |= 0x80; // MY bit for Y mirroring
    #endif

    st7789_write_data(madctl);

    // Configure pixel format
    st7789_write_command(0x3A); // COLMOD: Pixel Format Set
    st7789_write_data(0x55);    // 16-bit color format

    // Configure display inversion
    #ifdef DISPLAY_COLOR_INVERSION
        st7789_write_command(0x21); // Display Inversion On
    #else
        st7789_write_command(0x20); // Display Inversion Off
    #endif

    // Configure display timing and power
    st7789_write_command(0xB2); // Porch Setting
    st7789_write_data(0x0C);
    st7789_write_data(0x0C);
    st7789_write_data(0x00);
    st7789_write_data(0x33);
