bool InitializeCamera()
{
    // Step 1: Initialize I/O expander for power and reset control
    if (!InitializeIOExpander()) {
        return false;
    }

    // Step 2: Configure power and reset pins as outputs
    ConfigureIOExpanderPin(CAMERA_POWER_PIN, OUTPUT);
    ConfigureIOExpanderPin(CAMERA_RESET_PIN, OUTPUT);

    // Step 3: Power down sequence to ensure clean start
    SetIOExpanderPin(CAMERA_POWER_PIN, LOW);    // Power off
    SetIOExpanderPin(CAMERA_RESET_PIN, LOW);    // Reset low
    DelayMs(10);                                // Stabilization delay

    // Step 4: Power up sequence
    SetIOExpanderPin(CAMERA_POWER_PIN, HIGH);   // Power on
    DelayMs(10);                                // Wait for power stabilization

    // Step 5: Reset sequence
    SetIOExpanderPin(CAMERA_RESET_PIN, HIGH);   // Release reset
    DelayMs(5);                                 // Hold time
    SetIOExpanderPin(CAMERA_RESET_PIN, LOW);    // Assert reset
    DelayMs(1);                                 // Reset pulse width
    SetIOExpanderPin(CAMERA_RESET_PIN, HIGH);   // Release reset
    DelayMs(20);                                // Wait for camera startup

    // Step 6: Initialize DVP parallel interface
    if (!InitializeDVPInterface()) {
        return false;
    }

    // Step 7: Configure DVP pin mappings
    ConfigureDVPPins(DVP_DATA_PINS, DVP_CLOCK_PIN, DVP_HSYNC_PIN, DVP_VSYNC_PIN);

    // Step 8: Initialize SCCB/I2C interface
    if (!InitializeSCCBInterface()) {
        return false;
    }

    // Step 9: Configure SCCB/I2C parameters
    ConfigureSCCB(SCCB_SDA_PIN, SCCB_SCL_PIN, SCCB_FREQUENCY);

    // Step 10: Verify camera communication
    if (!VerifyCameraConnection()) {
        return false;
    }

    // Step 11: Create and configure camera driver instance
    if (!CreateCameraDriverInstance()) {
        return false;
    }

    // Step 12: Apply initial camera configuration
    if (!ConfigureCameraDriver()) {
        return false;
    }

    return true;
}

bool ReceiveWifiCredentialsFromAudio(Application* app, WifiManager* wifiManager, Display* display, size_t bufferSize) {
    // Initialize variables
    bool credentialsReceived = false;
    std::string ssid;
    std::string password;

    // Update display to show we're in config mode
    if (display) {
        display->ShowMessage("WiFi Config Mode", "Listening for credentials...");
    }

    // Configure audio input settings
    const int SAMPLE_RATE = 44100;  // Standard audio sample rate
    const int TARGET_SAMPLE_RATE = 8000;  // Downsampled rate for processing
    const int CHANNELS = 2;  // Assuming stereo input

    // Allocate buffers
    std::vector<int16_t> rawAudioBuffer(bufferSize * CHANNELS);
    std::vector<int16_t> monoAudioBuffer(bufferSize);
    std::vector<int16_t> downsampledBuffer(bufferSize / (SAMPLE_RATE / TARGET_SAMPLE_RATE));

    // Initialize audio capture
    AudioCapture audioCapture;
    if (!audioCapture.Initialize(SAMPLE_RATE, CHANNELS)) {
        if (display) {
            display->ShowMessage("Error", "Failed to initialize audio");
        }
        return false;
    }

    // Start capturing audio
    if (!audioCapture.Start()) {
        if (display) {
            display->ShowMessage("Error", "Failed to start audio capture");
        }
        return false;
    }

    // Set timeout for credential reception (e.g., 30 seconds)
    const int TIMEOUT_SECONDS = 30;
    auto startTime = std::chrono::steady_clock::now();

    // Main loop for receiving credentials
    while (!credentialsReceived && 
           (std::chrono::steady_clock::now() - startTime).count() < TIMEOUT_SECONDS * 1000000000LL) {

        // Read audio data
        size_t samplesRead = audioCapture.Read(rawAudioBuffer.data(), bufferSize);

        if (samplesRead > 0) {
            // Convert stereo to mono if needed
            if (CHANNELS == 2) {
                for (size_t i = 0; i < samplesRead; i++) {
                    // Simple averaging for stereo to mono conversion
                    monoAudioBuffer[i] = (rawAudioBuffer[i * 2] + rawAudioBuffer[i * 2 + 1]) / 2;
                }
            } else {
                // Already mono, just copy
                std::copy(rawAudioBuffer.begin(), rawAudioBuffer.begin() + samplesRead, monoAudioBuffer.begin());
            }

            // Downsample audio
            size_t downsampledCount = DownsampleAudio(monoAudioBuffer.data(), samplesRead, 
                                                     downsampledBuffer.data(), downsampledBuffer.size(),
                                                     SAMPLE_RATE, TARGET_SAMPLE_RATE);

            // Analyze audio for encoded credentials
            AudioCredentialDecoder decoder;
            CredentialData credentials;

            DecodeResult result = decoder.Decode(downsampledBuffer.data(), downsampledCount, credentials);

            if (result == DecodeResult::SUCCESS) {
                ssid = credentials.ssid;
                password = credentials.password;
                credentialsReceived = true;

                if (display) {
                    display->ShowMessage("Credentials Received", "Connecting to WiFi...");
                }
                break;
            } else if (result == DecodeResult::PARTIAL) {
                if (display) {
                    display->ShowMessage("Receiving...", "Detecting signal...");
                }
            }
        }

        // Check if application should exit config mode
        if (app && app->ShouldExitConfigMode()) {
            break;
        }

        // Small delay to prevent busy waiting
        std::this_thread::sleep_for(std::chrono::milliseconds(10));
    }

    // Stop audio capture
    audioCapture.Stop();

    // Process received credentials
    if (credentialsReceived && wifiManager && !ssid.empty()) {
        // Connect to WiFi network
        bool connected = wifiManager->ConnectToNetwork(ssid, password);

        if (connected) {
            if (display) {
                display->ShowMessage("Success", "Connected to WiFi: " + ssid);
            }
            return true;
        } else {
            if (display) {
                display->ShowMessage("Connection Failed", "Could not connect to: " + ssid);
            }
        }
    } else if (!credentialsReceived) {
        if (display) {
            display->ShowMessage("Timeout", "No credentials received");
        }
    }

    return false;
}

// Helper function for downsampling audio
size_t DownsampleAudio(const int16_t* input, size_t inputSize, int16_t* output, size_t outputSize, 
                      int inputRate, int targetRate) {
    if (inputRate <= targetRate) {
        // No downsampling needed, just copy
        size_t copySize = std::min(inputSize, outputSize);
        std::copy(input, input + copySize, output);
        return copySize;
    }

    int ratio = inputRate / targetRate;
    size_t outputSamples = std::min(inputSize / ratio, outputSize);

    for (size_t i = 0; i < outputSamples; i++) {
        // Simple decimation - take every nth sample
        output[i] = input[i * ratio];
    }

    return outputSamples;
}

std::vector<float> ProcessAudioSamples(const std::vector<float>& samples) {
    // Configuration parameters (typical values for audio processing)
    const int SAMPLE_RATE = 8000;           // 8kHz sample rate
    const float MARK_FREQ = 1200.0f;        // Mark frequency (Hz)
    const float SPACE_FREQ = 2200.0f;       // Space frequency (Hz)
    const int WINDOW_SIZE = 240;            // Window size for Goertzel processing
    const float THRESHOLD = 0.5f;           // Detection threshold

    std::vector<float> probabilities;

    // Return empty if not enough samples
    if (samples.size() < WINDOW_SIZE) {
        return probabilities;
    }

    // Pre-calculate Goertzel coefficients
    auto calculateCoefficient = [](float frequency, int N, int sampleRate) -> float {
        return 2.0f * cosf(2.0f * M_PI * frequency / sampleRate);
    };

    float coeffMark = calculateCoefficient(MARK_FREQ, WINDOW_SIZE, SAMPLE_RATE);
    float coeffSpace = calculateCoefficient(SPACE_FREQ, WINDOW_SIZE, SAMPLE_RATE);

    // Process samples in windows
    for (size_t i = 0; i <= samples.size() - WINDOW_SIZE; i += WINDOW_SIZE) {
        // Initialize Goertzel state variables for mark frequency
        float q0_mark = 0.0f, q1_mark = 0.0f, q2_mark = 0.0f;

        // Initialize Goertzel state variables for space frequency
        float q0_space = 0.0f, q1_space = 0.0f, q2_space = 0.0f;

        // Apply Goertzel algorithm for current window
        for (int n = 0; n < WINDOW_SIZE; n++) {
            float sample = samples[i + n];

            // Process mark frequency
            q0_mark = coeffMark * q1_mark - q2_mark + sample;
            q2_mark = q1_mark;
            q1_mark = q0_mark;

            // Process space frequency
            q0_space = coeffSpace * q1_space - q2_space + sample;
            q2_space = q1_space;
            q1_space = q0_space;
        }

        // Calculate final Goertzel magnitude for mark frequency
        float real_mark = q1_mark - q2_mark * cosf(2.0f * M_PI * MARK_FREQ / SAMPLE_RATE);
        float imag_mark = q2_mark * sinf(2.0f * M_PI * MARK_FREQ / SAMPLE_RATE);
        float magnitude_mark = sqrtf(real_mark * real_mark + imag_mark * imag_mark);
        float energy_mark = magnitude_mark * magnitude_mark;

        // Calculate final Goertzel magnitude for space frequency
        float real_space = q1_space - q2_space * cosf(2.0f * M_PI * SPACE_FREQ / SAMPLE_RATE);
        float imag_space = q2_space * sinf(2.0f * M_PI * SPACE_FREQ / SAMPLE_RATE);
        float magnitude_space = sqrtf(real_space * real_space + imag_space * imag_space);
        float energy_space = magnitude_space * magnitude_space;

        // Calculate probability of mark tone presence
        float total_energy = energy_mark + energy_space + 1e-10f; // Add small value to prevent division by zero
        float probability = energy_mark / total_energy;

        // Clamp probability between 0 and 1
        probability = fmaxf(0.0f, fminf(1.0f, probability));

        probabilities.push_back(probability);
    }

    return probabilities;
}

void ProcessProbabilityData(const std::vector<float>& probabilities, float threshold) {
    // Static variables to maintain state between calls
    static enum { INACTIVE, WAITING, RECEIVING } state = INACTIVE;
    static std::vector<int> bitBuffer;
    static std::vector<int> receivedData;

    // Predefined transmission identifiers (example patterns)
    static const std::vector<int> START_SEQUENCE = {1, 0, 1, 0, 1, 0, 1, 0};  // Example start pattern
    static const std::vector<int> END_SEQUENCE = {0, 1, 0, 1, 0, 1, 0, 1};    // Example end pattern

    // Convert probabilities to binary bits
    std::vector<int> currentBits;
    for (const float& prob : probabilities) {
        currentBits.push_back(prob >= threshold ? 1 : 0);
    }

    // Process each bit based on current state
    for (int bit : currentBits) {
        switch (state) {
            case INACTIVE:
                // Collect bits to check for start sequence
                bitBuffer.push_back(bit);
                if (bitBuffer.size() >= START_SEQUENCE.size()) {
                    // Check if we have a match with start sequence
                    bool startMatch = true;
                    for (size_t i = 0; i < START_SEQUENCE.size(); ++i) {
                        if (bitBuffer[bitBuffer.size() - START_SEQUENCE.size() + i] != START_SEQUENCE[i]) {
                            startMatch = false;
                            break;
                        }
                    }

                    if (startMatch) {
                        state = WAITING;
                        bitBuffer.clear();
                    } else {
                        // Remove oldest bit to maintain buffer size
                        if (!bitBuffer.empty()) {
                            bitBuffer.erase(bitBuffer.begin());
                        }
                    }
                }
                break;

            case WAITING:
                // Transition to receiving state and collect data
                state = RECEIVING;
                bitBuffer.push_back(bit);
                break;

            case RECEIVING:
                bitBuffer.push_back(bit);

                // Check for end sequence
                if (bitBuffer.size() >= END_SEQUENCE.size()) {
                    bool endMatch = true;
                    for (size_t i = 0; i < END_SEQUENCE.size(); ++i) {
                        if (bitBuffer[bitBuffer.size() - END_SEQUENCE.size() + i] != END_SEQUENCE[i]) {
                            endMatch = false;
                            break;
                        }
                    }

                    if (endMatch) {
                        // Extract data (excluding start and end sequences)
                        if (bitBuffer.size() > START_SEQUENCE.size() + END_SEQUENCE.size()) {
                            // Store the actual data (this is a simplified approach)
                            receivedData = bitBuffer;

                            // Optional checksum validation could be implemented here
                            // For example: validateChecksum(receivedData);

                            // Process the received data
                            processData(receivedData);
                        }

                        // Reset for next transmission
                        state = INACTIVE;
                        bitBuffer.clear();
                        receivedData.clear();
                    }
                }
                break;
        }
    }
}

