void Backlight::SetBrightness(uint8_t brightness, bool save) {
    // Clamp brightness to valid range
    if (brightness > 100) {
        brightness = 100;
    }

    // Prevent redundant updates
    if (brightness == mCurrentBrightness) {
        return;
    }

    // Save the target brightness
    mTargetBrightness = brightness;

    // Save setting permanently if requested
    if (save) {
        SaveBrightnessSetting(brightness);
    }

    // If already transitioning, just update the target
    if (mIsTransitioning) {
        return;
    }

    // Start smooth transition
    mIsTransitioning = true;
    mTransitionStep = (mTargetBrightness > mCurrentBrightness) ? 1 : -1;

    // Calculate step size for smooth transition
    uint8_t diff = (mTargetBrightness > mCurrentBrightness) ? 
                   (mTargetBrightness - mCurrentBrightness) : 
                   (mCurrentBrightness - mTargetBrightness);

    // Adjust step size based on difference for smoother animation
    if (diff > 50) {
        mTransitionStep *= 4;
    } else if (diff > 20) {
        mTransitionStep *= 2;
    }

    // Start the transition timer
    StartTransitionTimer();
}

// Helper method called by timer interrupt/callback
void Backlight::UpdateTransition() {
    if (!mIsTransitioning) {
        return;
    }

    // Update current brightness
    if (mTransitionStep > 0) {
        mCurrentBrightness += mTransitionStep;
        if (mCurrentBrightness >= mTargetBrightness) {
            mCurrentBrightness = mTargetBrightness;
            mIsTransitioning = false;
        }
    } else {
        mCurrentBrightness += mTransitionStep;
        if (mCurrentBrightness <= mTargetBrightness) {
            mCurrentBrightness = mTargetBrightness;
            mIsTransitioning = false;
        }
    }

    // Apply the new brightness to hardware
    ApplyHardwareBrightness(mCurrentBrightness);

    // Stop timer if transition is complete
    if (!mIsTransitioning) {
        StopTransitionTimer();
    }
}

// Helper method to apply brightness to hardware
void Backlight::ApplyHardwareBrightness(uint8_t brightness) {
    // Convert 0-100% to hardware-specific PWM value
    uint16_t pwmValue = (brightness * mMaxPWMValue) / 100;

    // Apply to hardware (implementation depends on specific hardware)
    SetPWMOutput(pwmValue);
}

// Helper method to save brightness setting
void Backlight::SaveBrightnessSetting(uint8_t brightness) {
    // Implementation depends on storage mechanism (EEPROM, flash, etc.)
    WriteToPersistentStorage(BRIGHTNESS_SETTING_ADDR, brightness);
}

PwmBacklight::PwmBacklight(gpio_num_t gpio_pin, bool inverted, uint32_t frequency_hz) {
    // Configure LEDC timer
    ledc_timer_config_t timer_conf = {};
    timer_conf.speed_mode = LEDC_LOW_SPEED_MODE;
    timer_conf.timer_num = LEDC_TIMER_0;
    timer_conf.duty_resolution = LEDC_TIMER_10_BIT;  // 10-bit resolution (0-1023)
    timer_conf.freq_hz = frequency_hz;
    timer_conf.clk_cfg = LEDC_AUTO_CLK;

    ledc_timer_config(&timer_conf);

    // Configure LEDC channel
    ledc_channel_config_t channel_conf = {};
    channel_conf.gpio_num = gpio_pin;
    channel_conf.speed_mode = LEDC_LOW_SPEED_MODE;
    channel_conf.channel = LEDC_CHANNEL_0;
    channel_conf.intr_type = LEDC_INTR_DISABLE;
    channel_conf.timer_sel = LEDC_TIMER_0;
    channel_conf.duty = 0;  // Start with 0% duty cycle (off)
    channel_conf.hpoint = 0;

    // Apply inversion if requested
    if (inverted) {
        channel_conf.flags.output_invert = 1;
    } else {
        channel_conf.flags.output_invert = 0;
    }

    ledc_channel_config(&channel_conf);

    // Store member variables
    this->gpio_pin_ = gpio_pin;
    this->inverted_ = inverted;
    this->frequency_hz_ = frequency_hz;
    this->channel_ = LEDC_CHANNEL_0;
    this->timer_ = LEDC_TIMER_0;

    // Initialize to 0% brightness
    set_brightness(0);
}

std::string Board::GenerateUuid() {
    uint8_t uuid[16];

    // Generate 16 random bytes using ESP32 hardware RNG
    for (int i = 0; i < 16; i++) {
        uuid[i] = esp_random() & 0xFF;
    }

    // Set UUID version to 4 (random) - bits 12-15 of byte 6 should be 0100
    uuid[6] = (uuid[6] & 0x0F) | 0x40;

    // Set UUID variant to RFC 4122 - bits 6-7 of byte 8 should be 10
    uuid[8] = (uuid[8] & 0x3F) | 0x80;

    // Format as hexadecimal string with hyphens
    char uuid_str[37]; // 36 chars + null terminator
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

String Board::GetSystemInfoJson() {
    // Create JSON document with sufficient capacity
    DynamicJsonDocument doc(2048);

    // Hardware Information
    JsonObject hardware = doc.createNestedObject("hardware");
    hardware["chip_model"] = ESP.getChipModel();
    hardware["chip_revision"] = ESP.getChipRevision();
    hardware["flash_size"] = ESP.getFlashChipSize();
    hardware["flash_speed"] = ESP.getFlashChipSpeed();
    hardware["cpu_freq"] = ESP.getCpuFreqMHz();

    // MAC Address
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    char macStr[18];
    sprintf(macStr, "%02X:%02X:%02X:%02X:%02X:%02X", 
            mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    hardware["mac_address"] = String(macStr);

    // Application Metadata
    JsonObject app = doc.createNestedObject("application");
    app["name"] = APP_NAME;
    app["version"] = APP_VERSION;
    app["compile_time"] = String(__DATE__) + " " + String(__TIME__);

    // Memory Information
    JsonObject memory = doc.createNestedObject("memory");
    memory["heap_size"] = ESP.getHeapSize();
    memory["free_heap"] = ESP.getFreeHeap();
    memory["min_free_heap"] = ESP.getMinFreeHeap();
    memory["psram_size"] = ESP.getPsramSize();
    memory["free_psram"] = ESP.getFreePsram();

    // Partition Information
    JsonObject partitions = doc.createNestedObject("partitions");

    // Sketch partition
    const esp_partition_t* running = esp_ota_get_running_partition();
    if (running) {
        JsonObject sketch = partitions.createNestedObject("sketch");
        sketch["address"] = running->address;
        sketch["size"] = running->size;
        sketch["label"] = running->label;
    }

    // OTA partitions
    const esp_partition_t* ota_0 = esp_partition_find_first(ESP_PARTITION_TYPE_APP, ESP_PARTITION_SUBTYPE_APP_OTA_0, NULL);
    const esp_partition_t* ota_1 = esp_partition_find_first(ESP_PARTITION_TYPE_APP, ESP_PARTITION_SUBTYPE_APP_OTA_1, NULL);

    if (ota_0) {
        JsonObject ota0 = partitions.createNestedObject("ota_0");
        ota0["address"] = ota_0->address;
        ota0["size"] = ota_0->size;
        ota0["label"] = ota_0->label;
    }

    if (ota_1) {
        JsonObject ota1 = partitions.createNestedObject("ota_1");
        ota1["address"] = ota_1->address;
        ota1["size"] = ota_1->size;
        ota1["label"] = ota_1->label;
    }

    // NVS partition
    const esp_partition_t* nvs = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_NVS, NULL);
    if (nvs) {
        JsonObject nvs_part = partitions.createNestedObject("nvs");
        nvs_part["address"] = nvs->address;
        nvs_part["size"] = nvs->size;
        nvs_part["label"] = nvs->label;
    }

    // System Runtime Info
    JsonObject system = doc.createNestedObject("system");
    system["uptime_ms"] = millis();
    system["reset_reason"] = rtc_get_reset_reason(0);

    // Generate UUID (using chip ID and MAC)
    uint64_t chipid = ESP.getEfuseMac();
    char uuidStr[37];
    sprintf(uuidStr, "%08X-%04X-%04X-%04X-%012llX",
            (uint32_t)(chipid >> 32),
            (uint16_t)((chipid >> 16) & 0xFFFF),
            (uint16_t)((chipid >> 0) & 0xFFFF),
            (uint16_t)(chipid & 0xFFFF),
            chipid);
    system["uuid"] = String(uuidStr);

    // WiFi Information
    JsonObject wifi = doc.createNestedObject("wifi");
    wifi["ssid"] = WiFi.SSID();
    wifi["rssi"] = WiFi.RSSI();
    wifi["ip_address"] = WiFi.localIP().toString();
    wifi["gateway"] = WiFi.gatewayIP().toString();

    // Convert to JSON string
    String jsonString;
    serializeJson(doc, jsonString);

    return jsonString;
}

Esp32Camera::Esp32Camera(const esp_video_init_config_t &config) 
    : fd_(-1), width_(0), height_(0), pixel_format_(0) {

    // Initialize member variables from config
    device_path_ = config.device_path ? std::string(config.device_path) : "/dev/video0";
    width_ = config.width;
    height_ = config.height;
    pixel_format_ = config.pixel_format;

    try {
        // Step 1: Open the video device
        fd_ = open(device_path_.c_str(), O_RDWR);
        if (fd_ < 0) {
            ESP_LOGE(TAG, "Failed to open video device %s: %s", device_path_.c_str(), strerror(errno));
            throw std::runtime_error("Failed to open device");
        }

        // Step 2: Query and validate device capabilities
        struct v4l2_capability cap;
        if (ioctl(fd_, VIDIOC_QUERYCAP, &cap) < 0) {
            ESP_LOGE(TAG, "Failed to query device capabilities: %s", strerror(errno));
            throw std::runtime_error("Failed to query capabilities");
        }

        // Check if this is a video capture device
        if (!(cap.capabilities & V4L2_CAP_VIDEO_CAPTURE)) {
            ESP_LOGE(TAG, "Device does not support video capture");
            throw std::runtime_error("Device doesn't support video capture");
        }

        // Check if streaming I/O is supported
        if (!(cap.capabilities & V4L2_CAP_STREAMING)) {
            ESP_LOGE(TAG, "Device does not support streaming I/O");
            throw std::runtime_error("Device doesn't support streaming");
        }

        // Step 3: Set the pixel format and resolution
        struct v4l2_format fmt;
        memset(&fmt, 0, sizeof(fmt));
        fmt.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
        fmt.fmt.pix.width = width_;
        fmt.fmt.pix.height = height_;
        fmt.fmt.pix.pixelformat = pixel_format_;
        fmt.fmt.pix.field = V4L2_FIELD_ANY;

        if (ioctl(fd_, VIDIOC_S_FMT, &fmt) < 0) {
            ESP_LOGE(TAG, "Failed to set pixel format: %s", strerror(errno));
            throw std::runtime_error("Failed to set format");
        }

        // Update actual dimensions (driver might adjust them)
        width_ = fmt.fmt.pix.width;
        height_ = fmt.fmt.pix.height;
        pixel_format_ = fmt.fmt.pix.pixelformat;

        ESP_LOGI(TAG, "Camera initialized successfully - Resolution: %dx%d, Format: %c%c%c%c",
                 width_, height_,
                 (pixel_format_ >> 0) & 0xFF,
                 (pixel_format_ >> 8) & 0xFF,
                 (pixel_format_ >> 16) & 0xFF,
                 (pixel_format_ >> 24) & 0xFF);

    } catch (const std::exception& e) {
        // Clean up resources on failure
        if (fd_ >= 0) {
            close(fd_);
            fd_ = -1;
        }
        throw; // Re-throw the exception
    }
}

esp_err_t Esp32Camera::Capture(camera_fb_t** out_framebuffer) {
    // Validate input parameters
    if (out_framebuffer == nullptr) {
        return ESP_ERR_INVALID_ARG;
    }

    *out_framebuffer = nullptr;

    // Wait for any previous encoding tasks to complete
    // This ensures proper synchronization
    if (this->encoding_semaphore != nullptr) {
        if (xSemaphoreTake(this->encoding_semaphore, pdMS_TO_TICKS(CAMERA_CAPTURE_TIMEOUT_MS)) != pdTRUE) {
            return ESP_ERR_TIMEOUT;
        }
    }

    // Acquire camera mutex to ensure exclusive access to camera hardware
    if (this->camera_mutex != nullptr) {
        if (xSemaphoreTake(this->camera_mutex, pdMS_TO_TICKS(CAMERA_CAPTURE_TIMEOUT_MS)) != pdTRUE) {
            if (this->encoding_semaphore != nullptr) {
                xSemaphoreGive(this->encoding_semaphore);
            }
            return ESP_ERR_TIMEOUT;
        }
    }

    esp_err_t result = ESP_OK;
    camera_fb_t* framebuffer = nullptr;

    // Set camera configuration if needed
    if (this->need_config_update) {
        result = esp_camera_init(&this->camera_config);
        if (result != ESP_OK) {
            goto cleanup;
        }
        this->need_config_update = false;
    }

    // Capture frame from camera hardware
    framebuffer = esp_camera_fb_get();
    if (framebuffer == nullptr) {
        result = ESP_FAIL;
        goto cleanup;
    }

    // Handle format conversion if required
    if (this->target_pixel_format != framebuffer->format) {
        result = ConvertPixelFormat(framebuffer, this->target_pixel_format);
        if (result != ESP_OK) {
            goto cleanup;
        }
    }

    // If PSRAM storage is requested and available, create a copy in PSRAM
    if (this->use_psram && psramFound()) {
        camera_fb_t* psram_framebuffer = AllocatePsramFramebuffer(framebuffer);
        if (psram_framebuffer != nullptr) {
            // Free the original framebuffer and use PSRAM version
            esp_camera_fb_return(framebuffer);
            framebuffer = psram_framebuffer;
        }
        // If PSRAM allocation fails, continue with original framebuffer
    }

    // Return the captured framebuffer
    *out_framebuffer = framebuffer;
    framebuffer = nullptr; // Prevent cleanup from freeing the returned buffer

cleanup:
    // Clean up temporary framebuffer if something failed
    if (framebuffer != nullptr) {
        esp_camera_fb_return(framebuffer);
    }

    // Release camera mutex
    if (this->camera_mutex != nullptr) {
        xSemaphoreGive(this->camera_mutex);
    }

    // Signal that capture is complete (release encoding semaphore)
    if (this->encoding_semaphore != nullptr) {
        xSemaphoreGive(this->encoding_semaphore);
    }

    return result;
}

// Helper function to allocate framebuffer in PSRAM
camera_fb_t* Esp32Camera::AllocatePsramFramebuffer(camera_fb_t* source) {
    if (source == nullptr) {
        return nullptr;
    }

    // Allocate framebuffer structure in PSRAM
    camera_fb_t* psram_fb = (camera_fb_t*)heap_caps_malloc(sizeof(camera_fb_t), MALLOC_CAP_SPIRAM);
    if (psram_fb == nullptr) {
        return nullptr;
    }

    // Allocate buffer in PSRAM
    uint8_t* psram_buffer = (uint8_t*)heap_caps_malloc(source->len, MALLOC_CAP_SPIRAM);
    if (psram_buffer == nullptr) {
        free(psram_fb);
        return nullptr;
    }

    // Copy data to PSRAM
    memcpy(psram_buffer, source->buf, source->len);

    // Initialize PSRAM framebuffer
    psram_fb->width = source->width;
    psram_fb->height = source->height;
    psram_fb->format = source->format;
    psram_fb->len = source->len;
    psram_fb->buf = psram_buffer;
    psram_fb->timestamp.tv_sec = source->timestamp.tv_sec;
    psram_fb->timestamp.tv_usec = source->timestamp.tv_usec;

    return psram_fb;
}

