bool Esp32Camera::Explain(const std::string& serverUrl) {
    // Initialize camera if not already done
    if (!cameraInitialized) {
        ESP_LOGE(TAG, "Camera not initialized");
        return false;
    }

    // Capture image from camera
    camera_fb_t* fb = esp_camera_fb_get();
    if (!fb) {
        ESP_LOGE(TAG, "Failed to capture image");
        return false;
    }

    // Check if captured image is already JPEG
    bool jpegEncoded = (fb->format == PIXFORMAT_JPEG);
    uint8_t* jpegBuf = nullptr;
    size_t jpegLen = 0;

    if (!jpegEncoded) {
        // Encode raw image to JPEG in separate thread
        jpegBuf = (uint8_t*)malloc(fb->width * fb->height / 3); // Estimate buffer size
        if (!jpegBuf) {
            ESP_LOGE(TAG, "Failed to allocate JPEG buffer");
            esp_camera_fb_return(fb);
            return false;
        }

        // Perform JPEG encoding (this would typically be done in a separate task/thread)
        bool encodeSuccess = frame2jpg(fb, 80, &jpegBuf, &jpegLen);
        if (!encodeSuccess) {
            ESP_LOGE(TAG, "JPEG encoding failed");
            free(jpegBuf);
            esp_camera_fb_return(fb);
            return false;
        }
    } else {
        // Image is already JPEG encoded
        jpegBuf = fb->buf;
        jpegLen = fb->len;
    }

    // Prepare HTTP client
    esp_http_client_config_t config = {};
    config.url = serverUrl.c_str();
    config.method = HTTP_METHOD_POST;

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        if (!jpegEncoded) free(jpegBuf);
        esp_camera_fb_return(fb);
        return false;
    }

    // Set headers
    esp_http_client_set_header(client, "Content-Type", "image/jpeg");
    esp_http_client_set_header(client, "User-Agent", "ESP32-Camera/1.0");

    // Add device identification
    char deviceId[32];
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    sprintf(deviceId, "ESP32-%02X%02X%02X", mac[3], mac[4], mac[5]);
    esp_http_client_set_header(client, "X-Device-ID", deviceId);

    // Add authentication token if available
    if (!authToken.empty()) {
        esp_http_client_set_header(client, "Authorization", ("Bearer " + authToken).c_str());
    }

    // Set post data
    esp_http_client_set_post_field(client, (const char*)jpegBuf, jpegLen);

    // Perform HTTP POST request
    esp_err_t err = esp_http_client_perform(client);
    bool success = false;

    if (err == ESP_OK) {
        int status_code = esp_http_client_get_status_code(client);
        if (status_code >= 200 && status_code < 300) {
            ESP_LOGI(TAG, "Image uploaded successfully, status=%d", status_code);
            success = true;
        } else {
            ESP_LOGE(TAG, "HTTP request failed, status=%d", status_code);
        }
    } else {
        ESP_LOGE(TAG, "HTTP request failed: %s", esp_err_to_name(err));
    }

    // Cleanup
    esp_http_client_cleanup(client);

    if (!jpegEncoded && jpegBuf) {
        free(jpegBuf);
    }

    esp_camera_fb_return(fb);

    return success;
}

void StartNetwork() {
    // Initialize WiFi manager with predefined SSID prefix and language
    WiFiManager wifiManager;

    // Set the SSID prefix for the configuration portal
    wifiManager.setAPNamePrefix("IoTDevice_");

    // Set language for the configuration portal (assuming English as default)
    wifiManager.setLanguage("en");

    // Set up unified event callback for handling WiFi events
    wifiManager.setEventCallback([](WiFiManagerEvent event, void* eventData) {
        switch(event) {
            case WIFI_MANAGER_EVENT_SCAN_STARTED:
                Serial.println("WiFi scan started");
                // Handle scanning start event
                break;

            case WIFI_MANAGER_EVENT_SCAN_COMPLETED:
                Serial.println("WiFi scan completed");
                // Handle scanning completion event
                break;

            case WIFI_MANAGER_EVENT_CONNECTING:
                Serial.println("Attempting WiFi connection...");
                // Handle connection attempt event
                break;

            case WIFI_MANAGER_EVENT_CONNECTED:
                Serial.println("WiFi connected successfully");
                Serial.print("IP Address: ");
                Serial.println(WiFi.localIP());
                // Handle successful connection event
                break;

            case WIFI_MANAGER_EVENT_DISCONNECTED:
                Serial.println("WiFi disconnected");
                // Handle disconnection event
                break;

            case WIFI_MANAGER_EVENT_CONFIG_MODE_STARTED:
                Serial.println("Configuration mode started");
                Serial.print("Config Portal IP: ");
                Serial.println(WiFi.softAPIP());
                // Handle configuration mode entry
                break;

            case WIFI_MANAGER_EVENT_CONFIG_MODE_EXITED:
                Serial.println("Configuration mode exited");
                // Handle configuration mode exit
                break;

            case WIFI_MANAGER_EVENT_CONNECTION_FAILED:
                Serial.println("WiFi connection failed");
                // Handle connection failure event
                break;

            default:
                Serial.println("Unknown WiFi event occurred");
                break;
        }
    });

    // Set timeout for configuration mode (e.g., 3 minutes)
    wifiManager.setConfigPortalTimeout(180);

    // Set minimum signal quality requirement (optional)
    wifiManager.setMinimumSignalQuality(20);

    // Set save parameters callback if needed
    wifiManager.setSaveConfigCallback([]() {
        Serial.println("Configuration saved");
    });

    // Attempt to connect to previously saved WiFi credentials
    // If no credentials exist or connection fails, start configuration portal
    if (!wifiManager.autoConnect()) {
        Serial.println("Failed to connect to WiFi and config portal timed out");
        // Handle the case where both auto-connect and config portal fail
        // This might involve retry logic or entering a low-power state
        delay(3000);
        ESP.restart(); // Restart device to try again
    } else {
        Serial.println("WiFi connected successfully");
        // Connection established, continue with normal operation
    }
}

void OnNetworkEvent(NetworkEvent event, const std::string &data) {
    // Update internal state based on event type
    switch (event) {
        case NetworkEvent::CONNECTED:
            // Update connection state
            isConnected = true;
            isInConfigMode = false;

            // Stop connection timeout timer
            StopConnectionTimer();

            // Release provisioning resources as we're now connected
            ReleaseProvisioningResources();

            // Reset reconnection attempt counter on successful connection
            reconnectionAttempts = 0;
            break;

        case NetworkEvent::DISCONNECTED:
            // Update connection state
            isConnected = false;

            // Stop any active timers
            StopConnectionTimer();

            // If we were in normal operation mode (not config), start reconnection logic
            if (!isInConfigMode) {
                StartReconnectionTimer();
            }
            break;

        case NetworkEvent::CONNECTION_FAILED:
            // Update connection state
            isConnected = false;

            // Stop connection timer
            StopConnectionTimer();

            // Increment reconnection attempt counter
            reconnectionAttempts++;

            // Schedule reconnection attempt if limit not reached
            if (reconnectionAttempts < MAX_RECONNECTION_ATTEMPTS) {
                StartReconnectionTimer();
            }
            break;

        case NetworkEvent::SCAN_STARTED:
            // Update scanning state
            isScanning = true;
            break;

        case NetworkEvent::SCAN_COMPLETED:
            // Update scanning state
            isScanning = false;

            // Stop scan timeout timer if active
            StopScanTimer();
            break;

        case NetworkEvent::SCAN_FAILED:
            // Update scanning state
            isScanning = false;

            // Stop scan timeout timer
            StopScanTimer();
            break;

        case NetworkEvent::CONFIG_MODE_ENTERED:
            // Update configuration mode state
            isInConfigMode = true;
            isConnected = false;  // Not connected to normal network in config mode

            // Stop normal operation timers
            StopConnectionTimer();
            StopReconnectionTimer();
            break;

        case NetworkEvent::CONFIG_MODE_EXITED:
            // Update configuration mode state
            isInConfigMode = false;

            // Attempt to connect to configured network
            StartConnectionTimer();
            break;

        default:
            // Handle unknown events gracefully
            break;
    }

    // Notify external callback if registered
    if (externalCallback != nullptr) {
        externalCallback(event, data);
    }
}

void StartWifiConfigMode() {
    // Set device state to configuring mode
    SetDeviceState(DEVICE_STATE_CONFIGURING);

    // Provide initial user feedback
    LedIndicator_SetPattern(LED_PATTERN_WIFI_CONFIG_START);

#ifdef ENABLE_HOTSPOT_PROVISIONING
    // Hotspot-based configuration with user prompts
    Log_Info("Starting hotspot provisioning mode");

    // Start WiFi hotspot service
    WifiHotspot_Start();

    // Display QR code or SSID/password information
    Display_ShowWifiConfigPrompt();

    // Start web server for configuration interface
    WebServer_Start(CONFIG_WEB_PORT);

    // Provide user feedback
    LedIndicator_SetPattern(LED_PATTERN_HOTSPOT_ACTIVE);
    Buzzer_Beep(BUZZER_PATTERN_SHORT, 2);

#elif defined(ENABLE_BLUFI_PROVISIONING)
    // Bluetooth Low Energy provisioning via Blufi
    Log_Info("Starting Blufi provisioning mode");

    // Initialize BLE stack
    Ble_Init();

    // Start Blufi service
    Blufi_Start();

    // Advertise BLE device for provisioning
    Ble_Advertise_Start(SERVICE_UUID_BLUFI);

    // Provide user feedback
    LedIndicator_SetPattern(LED_PATTERN_BLUETOOTH_ACTIVE);
    Buzzer_Beep(BUZZER_PATTERN_LONG, 1);

#elif defined(ENABLE_ACOUSTIC_PROVISIONING)
    // Acoustic provisioning through audio input
    Log_Info("Starting acoustic provisioning mode");

    // Initialize audio input subsystem
    AudioInput_Init();

    // Start audio capture for provisioning data
    AudioInput_StartCapture();

    // Enable acoustic provisioning decoder
    AcousticProvisioning_Start();

    // Provide user feedback
    LedIndicator_SetPattern(LED_PATTERN_AUDIO_ACTIVE);
    Display_ShowMessage("Listening for audio config...");

#else
    // Default fallback - hotspot provisioning
    Log_Warning("No provisioning method specified, using default hotspot mode");

    // Start WiFi hotspot service
    WifiHotspot_Start();

    // Display basic configuration prompt
    Display_ShowWifiConfigPrompt();

    // Start web server for configuration interface
    WebServer_Start(CONFIG_WEB_PORT);

    // Provide user feedback
    LedIndicator_SetPattern(LED_PATTERN_HOTSPOT_ACTIVE);
    Buzzer_Beep(BUZZER_PATTERN_SHORT, 3);
#endif

    // Notify system of configuration mode entry
    System_NotifyEvent(EVENT_WIFI_CONFIG_STARTED);

    // Start configuration timeout timer
    Timer_Start(CONFIG_TIMEOUT_TIMER, CONFIG_MODE_TIMEOUT_MS);
}

void EnterWifiConfigMode()
{
    // Validate current device state to prevent conflicts
    DeviceState currentState = GetCurrentDeviceState();
    if (currentState == STATE_CONFIG_MODE || currentState == STATE_UPDATING) {
        // Already in config mode or updating - prevent conflicts
        DisplayNotification("Already in configuration mode");
        return;
    }

    // Display notification about entering Wi-Fi config mode
    DisplayNotification("Entering Wi-Fi Configuration Mode...");

    // Reset active audio processes
    ShutdownAudioProcesses();

    // Reset active communication processes
    ShutdownCommunicationProcesses();

    // Additional cleanup - reset network connections
    DisconnectFromCurrentNetwork();

    // Update device state
    SetDeviceState(STATE_CONFIG_MODE);

    // Start the Wi-Fi configuration process
    StartWifiConfigurationProcess();

    // Final confirmation
    DisplayNotification("Wi-Fi Configuration Ready");
}

