            white_line[i] = 0xFFFF; // White color in RGB565
        }
        for (int y = 0; y < height; y++) {
            esp_lcd_panel_draw_bitmap(panel_handle, 0, y, width, y + 1, white_line);
        }
        free(white_line);
    }

    // Allocate display buffers for LVGL
    size_t buffer_size = width * height / 10; // Use 1/10 of screen size for buffer
    if (buffer_size > 0) {
        // Try to allocate in PSRAM first
        void *buf1 = heap_caps_malloc(buffer_size * sizeof(lv_color_t), MALLOC_CAP_SPIRAM);
        if (!buf1) {
            buf1 = heap_caps_malloc(buffer_size * sizeof(lv_color_t), MALLOC_CAP_INTERNAL);
        }

        void *buf2 = heap_caps_malloc(buffer_size * sizeof(lv_color_t), MALLOC_CAP_SPIRAM);
        if (!buf2) {
            buf2 = heap_caps_malloc(buffer_size * sizeof(lv_color_t), MALLOC_CAP_INTERNAL);
        }

        // Initialize LVGL display buffer
        lv_disp_draw_buf_init(&draw_buf, buf1, buf2, buffer_size);
    }

    // Initialize display driver for LVGL
    lv_disp_drv_init(&disp_drv);
    disp_drv.hor_res = width;
    disp_drv.ver_res = height;
    disp_drv.flush_cb = [](lv_disp_drv_t *drv, const lv_area_t *area, lv_color_t *color_map) {
        SpiLcdDisplay *display = (SpiLcdDisplay *)drv->user_data;
        int offset_x = area->x1;
        int offset_y = area->y1;
        int width = area->x2 - area->x1 + 1;
        int height = area->y2 - area->y1 + 1;

        esp_lcd_panel_draw_bitmap(display->panel_handle, 
                                  offset_x, offset_y, 
                                  offset_x + width, offset_y + height, 
                                  color_map);

        lv_disp_flush_ready(drv);
    };
    disp_drv.draw_buf = &draw_buf;
    disp_drv.user_data = this;

    // Set rotation based on parameters
    if (swap_xy) {
        disp_drv.sw_rotate = 1;
        disp_drv.rotated = LV_DISP_ROT_90;
    }

    // Register display with LVGL
    disp = lv_disp_drv_register(&disp_drv);

    // Apply additional orientation settings
    esp_lcd_panel_mirror(panel_handle, mirror_x, mirror_y);

    // Set screen orientation if supported by hardware
    if (swap_xy) {
        // Swap width and height for coordinate calculations
        int temp = this->width;
        this->width = this->height;
        this->height = temp;
    }
}

