MipiLcdDisplay::MipiLcdDisplay(
    esp_lcd_panel_io_handle_t io_handle,
    esp_lcd_panel_handle_t panel_handle,
    int width,
    int height,
    int offset_x,
    int offset_y,
    bool swap_xy,
    bool mirror_x,
    bool mirror_y)
    : io_handle_(io_handle)
    , panel_handle_(panel_handle)
    , width_(width)
    , height_(height)
    , offset_x_(offset_x)
    , offset_y_(offset_y)
    , swap_xy_(swap_xy)
    , mirror_x_(mirror_x)
    , mirror_y_(mirror_y)
{
    // Initialize LVGL
    lv_init();

    // Configure LCD panel dimensions and orientation
    esp_err_t err = ESP_OK;

    // Set display orientation and mirroring
    err = esp_lcd_panel_swap_xy(panel_handle_, swap_xy_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set swap xy: %s", esp_err_to_name(err));
        return;
    }

    err = esp_lcd_panel_mirror(panel_handle_, mirror_x_, mirror_y_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set mirror: %s", esp_err_to_name(err));
        return;
    }

    // Set window offset if supported
    err = esp_lcd_panel_set_gap(panel_handle_, offset_x_, offset_y_);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "Failed to set gap (offset): %s", esp_err_to_name(err));
        // Continue as this might not be critical
    }

    // Allocate frame buffer (assuming RGB565 format)
    size_t buffer_size = width_ * height_ * sizeof(uint16_t);
    draw_buffer_ = heap_caps_malloc(buffer_size, MALLOC_CAP_DMA);
    if (draw_buffer_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate draw buffer");
        return;
    }

    // Initialize LVGL display buffer
    lv_disp_draw_buf_init(&disp_buf_, draw_buffer_, nullptr, width_ * height_);

    // Initialize LVGL display driver
    lv_disp_drv_init(&disp_drv_);
    disp_drv_.hor_res = width_;
    disp_drv_.ver_res = height_;
    disp_drv_.flush_cb = flush_callback;
    disp_drv_.draw_buf = &disp_buf_;
    disp_drv_.user_data = this;

    // Register display driver with LVGL
    disp_ = lv_disp_drv_register(&disp_drv_);
    if (disp_ == nullptr) {
        ESP_LOGE(TAG, "Failed to register LVGL display driver");
        free(draw_buffer_);
        draw_buffer_ = nullptr;
        return;
    }

    // Setup user interface after successful display configuration
    setup_ui();
}

~LcdDisplay() {
    // Stop and delete the GIF controller first
    if (gifController != nullptr) {
        gifController->stop();
        delete gifController;
        gifController = nullptr;
    }

    // Remove all UI elements from the screen
    // Remove images
    for (auto image : images) {
        if (image != nullptr) {
            lv_obj_del(image);
        }
    }
    images.clear();

    // Remove labels
    for (auto label : labels) {
        if (label != nullptr) {
            lv_obj_del(label);
        }
    }
    labels.clear();

    // Remove bars
    for (auto bar : bars) {
        if (bar != nullptr) {
            lv_obj_del(bar);
        }
    }
    bars.clear();

    // Remove containers
    for (auto container : containers) {
        if (container != nullptr) {
            lv_obj_del(container);
        }
    }
    containers.clear();

    // Deallocate any remaining UI elements
    if (screen != nullptr) {
        lv_obj_clean(screen);
        screen = nullptr;
    }

    // Clean up timers
    for (auto timer : timers) {
        if (timer != nullptr) {
            lv_timer_del(timer);
        }
    }
    timers.clear();

    // Deallocate the underlying LCD panel
    if (lcdPanel != nullptr) {
        lcdPanel->deinit();
        delete lcdPanel;
        lcdPanel = nullptr;
    }

    // Deallocate panel IO drivers
    if (panelIO != nullptr) {
        panelIO->deinit();
        delete panelIO;
        panelIO = nullptr;
    }

    // Release any other associated objects
    // Clear any remaining collections
    uiElements.clear();
    resources.clear();
}

