void LcdDisplay::SetChatMessage(const char *message, const char *role) {
    // Check if message is empty
    if (message == nullptr || strlen(message) == 0) {
        return;
    }

    // Check if role is valid
    if (role == nullptr) {
        return;
    }

    // Determine if this is a system message
    bool isSystemMessage = (strcmp(role, "system") == 0);
    bool isUserMessage = (strcmp(role, "user") == 0);
    bool isAIMessage = (strcmp(role, "ai") == 0);

    // Hide AI logo for non-system messages
    if (!isSystemMessage) {
        HideAILogo();
    }

    // Manage message history - remove oldest if needed
    if (messageHistory.size() >= MAX_MESSAGE_HISTORY) {
        messageHistory.erase(messageHistory.begin());
    }

    // Create message entry
    MessageEntry entry;
    entry.content = std::string(message);
    entry.role = std::string(role);
    entry.timestamp = GetCurrentTime();

    // Add to history
    messageHistory.push_back(entry);

    // Calculate bubble dimensions based on message length
    int bubbleWidth = CalculateTextWidth(message) + BUBBLE_PADDING * 2;
    int bubbleHeight = CalculateTextHeight(message, bubbleWidth) + BUBBLE_PADDING * 2;

    // Determine positioning based on role
    int xPos, yPos;
    if (isUserMessage) {
        // User messages aligned to the right
        xPos = LCD_WIDTH - bubbleWidth - MARGIN_RIGHT;
    } else if (isSystemMessage) {
        // System messages centered
        xPos = (LCD_WIDTH - bubbleWidth) / 2;
    } else {
        // AI messages aligned to the left
        xPos = MARGIN_LEFT;
    }

    // Calculate vertical position (stacked from bottom)
    yPos = CalculateNextMessageYPosition(bubbleHeight);

    // Apply styling based on message type
    if (isSystemMessage) {
        // Special styling for system messages
        DrawSystemMessageBubble(xPos, yPos, bubbleWidth, bubbleHeight, message);
    } else if (isUserMessage) {
        // User message styling
        DrawUserMessageBubble(xPos, yPos, bubbleWidth, bubbleHeight, message);
    } else {
        // AI message styling
        DrawAIMessageBubble(xPos, yPos, bubbleWidth, bubbleHeight, message);
    }

    // Update display
    RefreshDisplay();
}

void SetPreviewImage(std::unique_ptr<LvglImage> image) {
    // Check if image is valid
    if (!image || !image->IsValid()) {
        LOG_WARNING("Invalid image provided for preview");
        return;
    }

    // Define maximum dimensions for preview
    constexpr int MAX_WIDTH = 300;
    constexpr int MAX_HEIGHT = 200;

    // Get original image dimensions
    int origWidth = image->GetWidth();
    int origHeight = image->GetHeight();

    // Validate original dimensions
    if (origWidth <= 0 || origHeight <= 0) {
        LOG_WARNING("Invalid image dimensions: %dx%d, using defaults", origWidth, origHeight);
        origWidth = 100;
        origHeight = 100;
    }

    // Calculate scaled dimensions maintaining aspect ratio
    int scaledWidth = origWidth;
    int scaledHeight = origHeight;

    if (scaledWidth > MAX_WIDTH || scaledHeight > MAX_HEIGHT) {
        float widthRatio = static_cast<float>(MAX_WIDTH) / scaledWidth;
        float heightRatio = static_cast<float>(MAX_HEIGHT) / scaledHeight;
        float scaleRatio = std::min(widthRatio, heightRatio);

        scaledWidth = static_cast<int>(scaledWidth * scaleRatio);
        scaledHeight = static_cast<int>(scaledHeight * scaleRatio);
    }

    // Ensure minimum size
    scaledWidth = std::max(scaledWidth, 50);
    scaledHeight = std::max(scaledHeight, 50);

    // Scale the image
    if (!image->Scale(scaledWidth, scaledHeight)) {
        LOG_WARNING("Failed to scale image to %dx%d", scaledWidth, scaledHeight);
        // Continue with original size if scaling fails
        scaledWidth = origWidth;
        scaledHeight = origHeight;
    }

    // Create message bubble container
    lv_obj_t* container = lv_obj_create(lv_scr_act());
    if (!container) {
        LOG_ERROR("Failed to create container for image preview");
        return;
    }

    // Set container size slightly larger than image for padding
    lv_obj_set_size(container, scaledWidth + 20, scaledHeight + 20);

    // Apply message bubble style
    static lv_style_t bubble_style;
    static bool style_initialized = false;

    if (!style_initialized) {
        lv_style_init(&bubble_style);
        lv_style_set_radius(&bubble_style, 10);
        lv_style_set_bg_color(&bubble_style, lv_color_hex(0xE0E0E0));
        lv_style_set_border_width(&bubble_style, 1);
        lv_style_set_border_color(&bubble_style, lv_color_hex(0xC0C0C0));
        lv_style_set_pad_all(&bubble_style, 10);
        style_initialized = true;
    }

    lv_obj_add_style(container, &bubble_style, 0);

    // Position container (centered or as per UI design)
    lv_obj_align(container, LV_ALIGN_CENTER, 0, 0);

    // Create image object within container
    lv_obj_t* img_obj = lv_img_create(container);
    if (!img_obj) {
        LOG_ERROR("Failed to create image object");
        lv_obj_del(container);
        return;
    }

    // Set image data
    lv_img_set_src(img_obj, image->GetImageData());

    // Center image within container
    lv_obj_align(img_obj, LV_ALIGN_CENTER, 0, 0);

    // Set up automatic cleanup using LVGL's user data feature
    // Store the image pointer in user data for cleanup
    lv_obj_set_user_data(container, image.get());

    // Set deletion callback to clean up image resource
    lv_obj_add_event_cb(container, [](lv_event_t* e) {
        lv_obj_t* obj = lv_event_get_target(e);
        void* user_data = lv_obj_get_user_data(obj);
        if (user_data) {
            LvglImage* img = static_cast<LvglImage*>(user_data);
            delete img; // Clean up the image resource
        }
    }, LV_EVENT_DELETE, nullptr);

    // Release ownership of the image since it's now managed by the container
    image.release();

    // Refresh display
    lv_refr_now(nullptr);
}

