void ParseServerHello(const cJSON *server_hello_json) {
    // Validate input parameter
    if (server_hello_json == NULL) {
        return;
    }

    // Extract server address
    cJSON *server_addr_obj = cJSON_GetObjectItemCaseSensitive(server_hello_json, "server_address");
    if (server_addr_obj != NULL && cJSON_IsString(server_addr_obj)) {
        const char *server_addr_str = cJSON_GetStringValue(server_addr_obj);
        // Assuming global variable or member variable exists to store this
        strncpy(udp_server_address, server_addr_str, sizeof(udp_server_address) - 1);
        udp_server_address[sizeof(udp_server_address) - 1] = '\0';
    }

    // Extract server port
    cJSON *server_port_obj = cJSON_GetObjectItemCaseSensitive(server_hello_json, "server_port");
    if (server_port_obj != NULL && cJSON_IsNumber(server_port_obj)) {
        udp_server_port = server_port_obj->valueint;
    }

    // Extract encryption key
    cJSON *encryption_key_obj = cJSON_GetObjectItemCaseSensitive(server_hello_json, "encryption_key");
    if (encryption_key_obj != NULL && cJSON_IsString(encryption_key_obj)) {
        const char *key_hex_str = cJSON_GetStringValue(encryption_key_obj);
        // Convert hex string to binary key (assuming 32-byte key for AES-256)
        size_t key_len = strlen(key_hex_str);
        if (key_len == 64) { // 32 bytes = 64 hex characters
            for (int i = 0; i < 32; i++) {
                sscanf(&key_hex_str[i * 2], "%2hhx", &aes_encryption_key[i]);
            }
        }
    }

    // Extract nonce/IV
    cJSON *nonce_obj = cJSON_GetObjectItemCaseSensitive(server_hello_json, "nonce");
    if (nonce_obj != NULL && cJSON_IsString(nonce_obj)) {
        const char *nonce_hex_str = cJSON_GetStringValue(nonce_obj);
        // Convert hex string to binary nonce (assuming 16 bytes for AES block size)
        size_t nonce_len = strlen(nonce_hex_str);
        if (nonce_len == 32) { // 16 bytes = 32 hex characters
            for (int i = 0; i < 16; i++) {
                sscanf(&nonce_hex_str[i * 2], "%2hhx", &aes_nonce[i]);
            }
        }
    }

    // Extract audio sample rate
    cJSON *sample_rate_obj = cJSON_GetObjectItemCaseSensitive(server_hello_json, "sample_rate");
    if (sample_rate_obj != NULL && cJSON_IsNumber(sample_rate_obj)) {
        audio_sample_rate = sample_rate_obj->valueint;
    }

    // Extract audio frame duration
    cJSON *frame_duration_obj = cJSON_GetObjectItemCaseSensitive(server_hello_json, "frame_duration");
    if (frame_duration_obj != NULL && cJSON_IsNumber(frame_duration_obj)) {
        audio_frame_duration_ms = frame_duration_obj->valueint;
    }

    // Initialize AES encryption with the extracted key and nonce
    aes_init_context(&aes_ctx, aes_encryption_key, aes_nonce);

    // Signal that server hello has been processed successfully
    server_hello_processed = 1;

    // Optional: Log successful parsing
    #ifdef DEBUG_LOGGING
    printf("Server Hello parsed successfully:\n");
    printf("  Server: %s:%d\n", udp_server_address, udp_server_port);
    printf("  Sample Rate: %d Hz\n", audio_sample_rate);
    printf("  Frame Duration: %d ms\n", audio_frame_duration_ms);
    #endif
}

void SendAudio(std::unique_ptr<AudioStreamPacket> audioPacket) {
    // Check if WebSocket connection is active
    if (!IsWebSocketConnected()) {
        // Log error or handle disconnected state
        return;
    }

    // Get the current protocol version
    ProtocolVersion version = GetNegotiatedProtocolVersion();

    // Prepare the binary payload based on protocol version
    std::vector<uint8_t> formattedPayload;

    if (version == PROTOCOL_V2) {
        // V2 protocol format
        // Header: [Version(1 byte)] [Payload Size(4 bytes)] [Timestamp(8 bytes)] [Audio Data]
        formattedPayload.push_back(0x02); // Protocol version identifier

        // Encode payload size (excluding header)
        uint32_t payloadSize = static_cast<uint32_t>(audioPacket->data.size());
        formattedPayload.push_back((payloadSize >> 24) & 0xFF);
        formattedPayload.push_back((payloadSize >> 16) & 0xFF);
        formattedPayload.push_back((payloadSize >> 8) & 0xFF);
        formattedPayload.push_back(payloadSize & 0xFF);

        // Encode timestamp (8 bytes)
        uint64_t timestamp = audioPacket->timestamp;
        for (int i = 7; i >= 0; i--) {
            formattedPayload.push_back((timestamp >> (i * 8)) & 0xFF);
        }

        // Append audio data
        formattedPayload.insert(formattedPayload.end(), 
                              audioPacket->data.begin(), 
                              audioPacket->data.end());
    }
    else if (version == PROTOCOL_V3) {
        // V3 protocol format
        // Header: [Version(1 byte)] [Flags(1 byte)] [Payload Size(4 bytes)] [Timestamp(8 bytes)] [Sequence Number(4 bytes)] [Audio Data]
        formattedPayload.push_back(0x03); // Protocol version identifier
        formattedPayload.push_back(audioPacket->flags & 0xFF); // Flags byte

        // Encode payload size
        uint32_t payloadSize = static_cast<uint32_t>(audioPacket->data.size());
        formattedPayload.push_back((payloadSize >> 24) & 0xFF);
        formattedPayload.push_back((payloadSize >> 16) & 0xFF);
        formattedPayload.push_back((payloadSize >> 8) & 0xFF);
        formattedPayload.push_back(payloadSize & 0xFF);

        // Encode timestamp
        uint64_t timestamp = audioPacket->timestamp;
        for (int i = 7; i >= 0; i--) {
            formattedPayload.push_back((timestamp >> (i * 8)) & 0xFF);
        }

        // Encode sequence number
        uint32_t sequenceNumber = audioPacket->sequenceNumber;
        formattedPayload.push_back((sequenceNumber >> 24) & 0xFF);
        formattedPayload.push_back((sequenceNumber >> 16) & 0xFF);
        formattedPayload.push_back((sequenceNumber >> 8) & 0xFF);
        formattedPayload.push_back(sequenceNumber & 0xFF);

        // Append audio data
        formattedPayload.insert(formattedPayload.end(), 
                              audioPacket->data.begin(), 
                              audioPacket->data.end());
    }
    else {
        // Raw payload format - send audio data directly
        formattedPayload.insert(formattedPayload.end(), 
                              audioPacket->data.begin(), 
                              audioPacket->data.end());
    }

    // Transmit the formatted payload over WebSocket
    SendWebSocketBinaryData(formattedPayload.data(), formattedPayload.size());
}

bool WebsocketProtocol::OpenAudioChannel()
{
    try {
        // Construct WebSocket URL for audio channel
        std::string wsUrl = "wss://" + m_serverAddress + "/audio";

        // Create WebSocket connection
        m_webSocket = std::make_unique<WebSocket>();
        if (!m_webSocket) {
            return false;
        }

        // Configure authentication headers
        m_webSocket->SetHeader("Authorization", "Bearer " + m_authToken);
        m_webSocket->SetHeader("X-Device-ID", m_deviceId);
        m_webSocket->SetHeader("X-Protocol-Version", std::to_string(m_protocolVersion));
        m_webSocket->SetHeader("User-Agent", "AudioClient/1.0");

        // Set up data handler for incoming messages
        m_webSocket->SetMessageHandler([this](const WebSocketMessage& message) {
            if (message.type == WebSocketMessageType::Binary) {
                ProcessAudioPacket(message.data, message.length);
            } else if (message.type == WebSocketMessageType::Text) {
                ProcessControlMessage(message.data);
            }
        });

        // Set up connection state handlers
        m_webSocket->SetConnectionHandler([this](bool connected) {
            m_isConnected = connected;
            if (connected) {
                // Notify that audio channel is ready
                OnAudioChannelReady();
            }
        });

        m_webSocket->SetErrorHandler([this](const std::string& error) {
            m_lastError = error;
            m_isConnected = false;
        });

        // Establish WebSocket connection
        if (!m_webSocket->Connect(wsUrl)) {
            m_lastError = "Failed to connect to audio WebSocket";
            return false;
        }

        // Verify connection is established
        if (!m_webSocket->IsConnected()) {
            m_lastError = "WebSocket connection not established";
            return false;
        }

        m_audioChannelOpen = true;
        return true;

    } catch (const std::exception& e) {
        m_lastError = "Exception in OpenAudioChannel: " + std::string(e.what());
        return false;
    } catch (...) {
        m_lastError = "Unknown exception in OpenAudioChannel";
        return false;
    }
}

void WebsocketProtocol::ProcessAudioPacket(const uint8_t* data, size_t length)
{
    if (length < sizeof(AudioPacketHeader)) {
        return; // Invalid packet
    }

    switch (m_protocolVersion) {
        case 2:
            ProcessAudioPacketV2(data, length);
            break;
        case 3:
            ProcessAudioPacketV3(data, length);
            break;
        default:
            m_lastError = "Unsupported protocol version: " + std::to_string(m_protocolVersion);
            break;
    }
}

void WebsocketProtocol::ProcessAudioPacketV2(const uint8_t* data, size_t length)
{
    // V2 protocol specific packet processing
    const AudioPacketHeaderV2* header = reinterpret_cast<const AudioPacketHeaderV2*>(data);

    // Convert from network byte order if needed
    uint16_t packetSize = ntohs(header->packetSize);
    uint32_t timestamp = ntohl(header->timestamp);

    // Extract payload
    const uint8_t* payload = data + sizeof(AudioPacketHeaderV2);
    size_t payloadSize = packetSize - sizeof(AudioPacketHeaderV2);

    if (payloadSize > 0 && payloadSize <= (length - sizeof(AudioPacketHeaderV2))) {
        // Process the audio payload
        HandleAudioData(payload, payloadSize, timestamp);
    }
}

void WebsocketProtocol::ProcessAudioPacketV3(const uint8_t* data, size_t length)
{
    // V3 protocol specific packet processing
    const AudioPacketHeaderV3* header = reinterpret_cast<const AudioPacketHeaderV3*>(data);

    // Convert from network byte order if needed
    uint32_t packetSize = ntohl(header->packetSize);
    uint64_t timestamp = be64toh(header->timestamp); // Assuming big-endian for v3

    // Extract payload with additional metadata
    const uint8_t* payload = data + sizeof(AudioPacketHeaderV3);
    size_t payloadSize = packetSize - sizeof(AudioPacketHeaderV3);

    if (payloadSize > 0 && payloadSize <= (length - sizeof(AudioPacketHeaderV3))) {
        // Process the audio payload with codec info
        HandleAudioDataV3(payload, payloadSize, timestamp, header->codecType, header->channelInfo);
    }
}

